static int read_line(char *dest, size_t dest_sz) {
    char tmp[INPUT_BUF_SIZE];

    if (fgets(tmp, sizeof(tmp), stdin) == NULL) {
        return 0;   /* EOF or error */
    }

    /* Remove possible newline */
    size_t len = strcspn(tmp, "\r\n");
    tmp[len] = '\0';

    /* Truncate to destination size (leaving room for '\0') */
    if (len >= dest_sz) {
        /* Input too long – truncate safely */
        len = dest_sz - 1;
    }
    memcpy(dest, tmp, len + 1);   /* copy including terminating '\0' */
    return 1;
}

/* Helper: parse a double from a string, with strict error checking */
static int parse_double(const char *src, double *out) {
    char *endptr = NULL;
    errno = 0;
    double val = strtod(src, &endptr);

    if (errno != 0 || endptr == src || *endptr != '\0') {
        return 0;   /* conversion failed */
    }
    *out = val;
    return 1;
}

/* Helper: parse an int (date) from a string, with strict error checking */
static int parse_int(const char *src, int *out) {
    char *endptr = NULL;
    errno = 0;
    long val = strtol(src, &endptr, 10);

