 */
void print_map(const Room *room)
{
    /* --------------------------------------------------------------------
     * 1️⃣  Null‑pointer guard – prevents dereference of a NULL pointer.
     * -------------------------------------------------------------------- */
    if (room == NULL) {
        fprintf(stderr, "Error: print_map received a NULL Room pointer.\n");
        return;
    }

    /* --------------------------------------------------------------------
     * 2️⃣  Coordinate validation – protects against out‑of‑range values that
     *     could otherwise cause the highlighted cell to be placed outside the
     *     printed grid.
     * -------------------------------------------------------------------- */
    if (room->x < 0 || room->x >= MAX_ROOMS ||
        room->y < 0 || room->y >= MAX_ROOMS) {
        fprintf(stderr,
                "Error: Room coordinates (%d,%d) are outside the map bounds "
                "(0‑%d).\n",
                room->x, room->y, MAX_ROOMS - 1);
        return;
    }

    /* --------------------------------------------------------------------
     * 3️⃣  Map rendering – safe nested loops with clear bounds.
     * -------------------------------------------------------------------- */
    for (int y = 0; y < MAX_ROOMS; ++y) {
        for (int x = 0; x < MAX_ROOMS; ++x) {
            if (room->x == x && room->y == y) {
                printf("O ");          /* Highlighted room */
            } else {
                printf(". ");          /* Empty cell */
            }
        }
        printf("\n");                  /* End of row */
    }
