#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <limits.h>
#include <arpa/inet.h>
#include <unistd.h>
#include <sys/socket.h>

#define MAX_PORTS 1000          /* example upper bound – adjust as needed */
#define MIN_PORT   1
#define MAX_PORT   65535

int main(int argc, char *argv[])
{
    /* -------------------------------------------------------------
     * 1️⃣  Validate command‑line arguments
     * ------------------------------------------------------------- */
    if (argc < 3) {
        fprintf(stderr,
                "Usage: %s <IP-address> <start‑port>\n", argv[0]);
        return EXIT_FAILURE;                     /* CWE‑20: Improper Input Validation */
    }

    /* -------------------------------------------------------------
     * 2️⃣  Parse and validate the IP address safely
     * ------------------------------------------------------------- */
    struct sockaddr_in server;
    memset(&server, 0, sizeof(server));
    server.sin_family = AF_INET;

    if (inet_pton(AF_INET, argv[1], &server.sin_addr) != 1) {
        fprintf(stderr, "Invalid IPv4 address: %s\n", argv[1]);
        return EXIT_FAILURE;                     /* CWE‑118: Improper Input Validation */
    }

    /* -------------------------------------------------------------
     * 3️⃣  Parse and validate the start port (use strtol, not atoi)
     * ------------------------------------------------------------- */
    char *endptr = NULL;
    errno = 0;
    long start_port_l = strtol(argv[2], &endptr, 10);

    if (errno != 0 || endptr == argv[2] || *endptr != '\0') {
        fprintf(stderr, "Port must be a decimal number: %s\n", argv[2]);
        return EXIT_FAILURE;                     /* CWE‑20 */
    }

    if (start_port_l < MIN_PORT || start_port_l > MAX_PORT) {
        fprintf(stderr,
                "Port out of range (%d‑%d): %ld\n",
                MIN_PORT, MAX_PORT, start_port_l);
        return EXIT_FAILURE;                     /* CWE‑20 */
    }

    /* -------------------------------------------------------------
     * 4️⃣  Compute the end port and ensure we stay within bounds
     * ------------------------------------------------------------- */
    long end_port_l = start_port_l + MAX_PORTS - 1;
    if (end_port_l > MAX_PORT) {
        end_port_l = MAX_PORT;                    /* clamp to the maximum allowed */
    }

    /* Store the validated start port in the sockaddr (network byte order) */
    server.sin_port = htons((uint16_t)start_port_l);

    /* -------------------------------------------------------------
     * 5️⃣  Create the socket – check for errors explicitly
     * ------------------------------------------------------------- */
    int sock = socket(AF_INET, SOCK_STREAM, 0);
    if (sock == -1) {
        perror("socket");
        return EXIT_FAILURE;                     /* CWE‑190: Check return values */
    }

    /* -------------------------------------------------------------
     * 6️⃣  (Optional) Connect / bind / further processing …
     * ------------------------------------------------------------- */
    /* Example: attempt a connection to verify the address/port */
    if (connect(sock, (struct sockaddr *)&server, sizeof(server)) == -1) {
        perror("connect");
        close(sock);
        return EXIT_FAILURE;                     /* CWE‑400: Proper error handling */
    }

    /* … continue with your logic … */

    close(sock);
    return EXIT_SUCCESS;
}
```

### What the remediation addresses

