static int read_line(char *buf, size_t buflen)
{
    if (fgets(buf, (int)buflen, stdin) == NULL) {
        return -1;                     /* EOF or error */
    }
    /* Strip trailing newline, if present */
    size_t len = strlen(buf);
    if (len > 0 && buf[len - 1] == '\n')
        buf[len - 1] = '\0';
    return 0;
}

/* Helper: parse an integer with range checking */
static int parse_int(const char *s, int *out, int min, int max)
{
    char *endptr = NULL;
    long val;

    errno = 0;
    val = strtol(s, &endptr, 10);

    /* Detect conversion errors */
    if (errno != 0 || endptr == s || *endptr != '\0')
        return -1;

    if (val < min || val > max)
        return -1;

    *out = (int)val;
    return 0;
}

/* Helper: parse a floating‑point number with range checking */
static int parse_float(const char *s, float *out, float min)
{
    char *endptr = NULL;
    double val;

    errno = 0;
    val = strtod(s, &endptr);

    if (errno != 0 || endptr == s || *endptr != '\0')
        return -1;

    if (val < min || val > FLT_MAX)
        return -1;

    *out = (float)val;
    return 0;
}

