 *  Secure floating‑point arithmetic for the RC‑LC simulation
 * -------------------------------------------------------------
 *  Return codes:
 *      0  – success
 *     -1  – invalid input (zero/negative parameters)
 *     -2  – arithmetic overflow/under‑flow detected
 * ------------------------------------------------------------- */

#include <math.h>
#include <float.h>
#include <stdbool.h>
#include <stddef.h>

/* Helper: safe division that detects overflow, under‑flow and zero‑divisor */
static inline int safe_div(double numerator,
                           double denominator,
                           double *result)
{
    if (denominator == 0.0) {
        return -1;                     /* division by zero */
    }

    double tmp = numerator / denominator;

    /* IEEE‑754 guarantees that overflow yields ±Inf and under‑flow yields 0.
       We treat any non‑finite result as an error. */
    if (!isfinite(tmp)) {
        return -2;                     /* overflow / under‑flow */
    }

    *result = tmp;
    return 0;
}

/* Helper: safe exponential that caps the exponent to a range that
   cannot overflow the double representation. */
static inline int safe_exp(double exponent, double *result)
{
    /* The largest exponent that still yields a finite double is
       roughly log(DBL_MAX) ≈ 709.78.  Anything larger will overflow to Inf. */
    const double EXP_MAX = 709.0;   /* conservative margin */
    const double EXP_MIN = -709.0;  /* under‑flow to 0 is acceptable, but we cap */

    if (exponent > EXP_MAX) {
        return -2;                 /* overflow */
    }
    if (exponent < EXP_MIN) {
        /* Under‑flow to 0 is mathematically fine; we clamp to 0.0 */
        *result = 0.0;
        return 0;
    }

    double tmp = exp(exponent);
    if (!isfinite(tmp)) {
        return -2;                 /* unexpected non‑finite result */
    }
    *result = tmp;
    return 0;
}

