                 double t,          /* current simulation time (seconds) */
                 double Vs_pulse,   /* input pulse amplitude (volts)      */
                 double L1_current, /* inductance (henries)               */
                 double R2,         /* resistance in the exponential term */
                 double R1,         /* load resistance (ohms)             */
                 double *dt,        /* out: time step                     */
                 double *Vout,      /* out: voltage across C1             */
                 double *Iout)      /* out: current through L1            */
{
