        return -1;                     /* null pointer */
    }

    /* -----------------------------------------------------------------
     *  1. Validate input parameters – they must be positive and finite.
     * ----------------------------------------------------------------- */
    if (T <= 0.0 || t < 0.0 || Vs_pulse < 0.0 ||
        L1_current <= 0.0 || R2 <= 0.0 || R1 <= 0.0 ||
        !isfinite(T) || !isfinite(t) || !isfinite(Vs_pulse) ||
        !isfinite(L1_current) || !isfinite(R2) || !isfinite(R1))
    {
        return -1;
    }

    /* -------------------------------------------------
     *  2. Calculate the time step (no overflow risk here)
     * ------------------------------------------------- */
    *dt = T;   /* direct assignment – already validated */

    /* -------------------------------------------------
     *  3. Compute the exponent:  -t / (L1_current * R2)
     * ------------------------------------------------- */
    double denom;
    int rc = safe_div(L1_current * R2, 1.0, &denom);   /* denom = L1_current * R2 */
    if (rc != 0) {
        return rc;   /* should never happen because we validated inputs */
    }

    double exponent;
    rc = safe_div(-t, denom, &exponent);
    if (rc != 0) {
        return rc;   /* division by zero or overflow */
    }

    /* -------------------------------------------------
     *  4. Compute exp(exponent) safely
     * ------------------------------------------------- */
    double exp_val;
    rc = safe_exp(exponent, &exp_val);
    if (rc != 0) {
        return rc;   /* overflow/under‑flow in exp */
    }

    /* -------------------------------------------------
     *  5. Vout = Vs_pulse * (1 - exp_val)
     * ------------------------------------------------- */
    double one_minus_exp = 1.0 - exp_val;
    if (!isfinite(one_minus_exp)) {
        return -2;   /* should not happen, but guard anyway */
    }

    double vtmp = Vs_pulse * one_minus_exp;
    if (!isfinite(vtmp)) {
        return -2;   /* overflow in multiplication */
    }
