     *  6. Iout = Vout / R1   (safe division)
     * ------------------------------------------------- */
    rc = safe_div(*Vout, R1, Iout);
    if (rc != 0) {
        return rc;   /* division by zero or overflow */
    }

    return 0;   /* success */
}
