    g->width  = WIDTH;
    g->height = HEIGHT;

    /* Guard against width*height overflow */
    if (!safe_mul_u32(g->width, g->height, &total_cells)) {
        fprintf(stderr, "grid dimensions overflow\n");
        free(g);
        return NULL;
    }

    /* Allocate the flat array of cell pointers (one pointer per cell) */
    g->grid = (cell_t **)calloc((size_t)total_cells, sizeof(cell_t *));
    if (g->grid == NULL) {
        perror("calloc(grid->grid)");
        free(g);
        return NULL;
    }

    /* Initialise each cell */
    for (uint32_t i = 0; i < g->width; ++i) {
        for (uint32_t j = 0; j < g->height; ++j) {
            uint32_t idx = i * g->height + j;   /* row‑major indexing */

            /* Allocate the cell itself */
            cell_t *c = (cell_t *)malloc(sizeof(*c));
            if (c == NULL) {
                perror("malloc(cell_t)");
                /* Clean‑up everything allocated so far */
                for (uint32_t k = 0; k < idx; ++k) {
                    free(g->grid[k]);
                }
                free(g->grid);
                free(g);
                return NULL;
            }

            /* Populate the cell – no arithmetic overflow because i,j < WIDTH/HEIGHT */
            c->x = i * CELL_SIZE;
            c->y = j * CELL_SIZE;
            c->alive = 1U;

            g->grid[idx] = c;
        }
    }

    return g;
}

/* ---------------------------------------------------------------------------
 * Release all memory owned by a grid.
 * --------------------------------------------------------------------------- */
static void grid_destroy(grid_t *g)
{
    if (g == NULL) {
        return;
    }

    uint32_t total_cells = g->width * g->height;
    for (uint32_t i = 0; i < total_cells; ++i) {
        free(g->grid[i]);          /* free each cell (NULL is safe) */
    }
    free(g->grid);                /* free the pointer array */
    free(g);                      /* free the container itself */
}

