## 4. Safe parsing routine

```c
#include <stdio.h>
#include <string.h>
#include <time.h>
#include <stdbool.h>

/* Helper: safely copy a parsed token into the destination buffer.
 * Returns true on success, false if the token would overflow. */
static bool safe_copy(char *dest, size_t dest_sz, const char *src)
{
    /* `dest_sz` includes space for the terminating NUL. */
    if (strlen(src) >= dest_sz) {
        return false;               /* overflow would occur */
    }
    memcpy(dest, src, strlen(src) + 1); /* copy including NUL */
    return true;
}

/* Main processing loop – replaces the vulnerable sscanf usage. */
void process_log(FILE *fp, time_t now)
{
    char line[MAX_LINE];
    log_entry_t entry;

    if (fp == NULL) {
        fprintf(stderr, "Error: could not open log file\n");
        return;
    }

    while (fgets(line, sizeof(line), fp) != NULL) {
        char ip_tmp[IP_MAX_LEN];
        char method_tmp[METHOD_MAX_LEN];
        char url_tmp[URL_MAX_LEN];
        char ua_tmp[UA_MAX_LEN];

        /* Use width specifiers that match the temporary buffers.
         * The leading space in the format string skips any leading whitespace. */
        int fields = sscanf(line,
                            " %45s %15s %2082s [%1023[^]]]",
                            ip_tmp, method_tmp, url_tmp, ua_tmp);

        if (fields != 4) {
            fprintf(stderr, "Error: invalid log entry (wrong field count)\n");
            continue;
        }

        /* Verify each token fits its final destination (defense‑in‑depth). */
        if (!safe_copy(entry.ip,        sizeof(entry.ip),        ip_tmp) ||
            !safe_copy(entry.method,    sizeof(entry.method),    method_tmp) ||
            !safe_copy(entry.url,       sizeof(entry.url),       url_tmp) ||
            !safe_copy(entry.user_agent, sizeof(entry.user_agent), ua_tmp)) {
            fprintf(stderr, "Error: log entry contains over‑long fields\n");
            continue;
        }

        entry.timestamp = now;
        analyze_log_entry(&entry);   /* existing analysis routine */
    }
}
```

