static int get_user_choice(void)
{
    char buf[INPUT_BUF_SIZE];
    long val;
    char *endptr;

    while (1) {
        /* Prompt the user */
        printf("Choose an option:\n");
        printf("1. Add email\n");
        printf("2. Display emails\n");
        printf("3. Exit\n");
        fflush(stdout);               /* ensure prompt is shown before input */

        /* Read a line, bounded by INPUT_BUF_SIZE */
        if (fgets(buf, sizeof(buf), stdin) == NULL) {
            /* EOF or read error – treat as exit */
            fprintf(stderr, "Input error – terminating.\n");
            exit(EXIT_FAILURE);
