        /* Ensure the whole line was a valid integer (no extra chars) */
        while (isspace((unsigned char)*endptr)) endptr++;   /* skip trailing spaces */
        if (*endptr != '\0') {
            fprintf(stderr, "Invalid characters detected. Please enter a numeric option.\n");
            continue;
        }

        /* At this point we have a safe integer */
        return (int)val;
    }
}

