#include <sys/resource.h>
#include <sys/time.h>
#include <errno.h>
#include <stddef.h>
#include <stdint.h>

/**
 * @brief Computes the CPU usage percentage of the current process.
 *
 * The function safely handles very large runtimes and protects against
 * division‑by‑zero. It returns a negative value on error (e.g., -1.0) and
 * sets `errno` accordingly.
 *
 * @param[out] cpu_pct  Pointer that receives the CPU usage percentage.
 * @return 0 on success, -1 on failure (errno set).
 */
int get_cpu_usage_percent(double *cpu_pct)
{
    if (cpu_pct == NULL) {
        errno = EINVAL;
        return -1;
    }

    struct rusage usage;
    struct timeval now;
    int rc;

    /* 1️⃣  Gather resource usage */
    rc = getrusage(RUSAGE_SELF, &usage);
    if (rc != 0) {
        /* getrusage failed – propagate the system error */
        return -1;
    }

    /* 2️⃣  Capture the current wall‑clock time */
    rc = gettimeofday(&now, NULL);
    if (rc != 0) {
        return -1;
    }

    /* -----------------------------------------------------------------
     * 3️⃣  Accumulate CPU time in *nanoseconds* using 64‑bit arithmetic.
     *     This avoids intermediate floating‑point overflow.
     * ----------------------------------------------------------------- */
    uint64_t cpu_user_ns  = (uint64_t)usage.ru_utime.tv_sec  * 1000000000ULL
                          + (uint64_t)usage.ru_utime.tv_usec * 1000ULL;
    uint64_t cpu_sys_ns   = (uint64_t)usage.ru_stime.tv_sec  * 1000000000ULL
                          + (uint64_t)usage.ru_stime.tv_usec * 1000ULL;
    uint64_t cpu_total_ns = cpu_user_ns + cpu_sys_ns;   /* safe: 64‑bit */

    /* -----------------------------------------------------------------
     * 4️⃣  Convert elapsed wall‑clock time to nanoseconds.
     * ----------------------------------------------------------------- */
    uint64_t elapsed_ns = (uint64_t)now.tv_sec  * 1000000000ULL
                        + (uint64_t)now.tv_usec * 1000ULL;

    /* -----------------------------------------------------------------
     * 5️⃣  Defensive check – avoid division by zero.
     * ----------------------------------------------------------------- */
    if (elapsed_ns == 0) {
        /* Process started less than a microsecond ago – report 0% usage. */
        *cpu_pct = 0.0;
        return 0;
    }

    /* -----------------------------------------------------------------
     * 6️⃣  Perform the division in double precision *once*.
     * ----------------------------------------------------------------- */
    double cpu_fraction = (double)cpu_total_ns / (double)elapsed_ns;

    /* Clamp the fraction to the valid range [0.0, 1.0] in case of
       unexpected timer anomalies (e.g., clock adjustments). */
    if (cpu_fraction < 0.0) cpu_fraction = 0.0;
    if (cpu_fraction > 1.0) cpu_fraction = 1.0;

    *cpu_pct = cpu_fraction * 100.0;   /* convert to percentage */

    return 0;
}
```

#### Why this remediation is secure

1. **Overflow protection** – All intermediate arithmetic is performed in unsigned 64‑bit integers (`uint64_t`). The maximum representable nanoseconds (`~1.8 × 10¹⁹`) comfortably exceeds any realistic process lifetime (≈ 584 years), eliminating overflow risk.

2. **Division‑by‑zero safety** – The function explicitly checks `elapsed_ns == 0` before any division, returning a deterministic `0.0 %` usage instead of triggering undefined behavior.

3. **Error handling** – Both `getrusage` and `gettimeofday` return values are verified; on failure the function propagates `errno` so callers can react appropriately.

4. **Single conversion to floating point** – Converting to `double` only once (after the safe integer math) reduces rounding error and prevents overflow in the floating‑point domain.

5. **Input validation** – The output pointer is validated (`cpu_pct != NULL`) to avoid dereferencing a null pointer.

6. **Clamping** – The final fraction is bounded to `[0, 1]` to guard against pathological clock adjustments that could otherwise produce a percentage > 100 % or < 0 %.

7. **No external dependencies** – The code relies solely on standard POSIX APIs, avoiding the introduction of third‑party libraries that could contain hidden vulnerabilities.

