/* -------------------------------------------------------------------------
 * Queue data‑structure (example)
 * -------------------------------------------------------------------------
 * MAX_QUEUE_SIZE must be a positive integer > 0.
 * The queue is considered empty when front == -1 && rear == -1.
 * ------------------------------------------------------------------------- */
typedef struct {
    int  data[MAX_QUEUE_SIZE];
    int  front;      /* index of the first element */
    int  rear;       /* index of the last element  */
} queue_t;

/* -------------------------------------------------------------------------
 * Helper: validate a queue pointer.
 * Returns true if the pointer is non‑NULL and the internal indices are in
 * the legal range; otherwise returns false.
 * ------------------------------------------------------------------------- */
static inline bool queue_is_valid(const queue_t *queue)
{
    if (queue == NULL) {
        return false;
    }

    /* front and rear must be either -1 (empty) or a valid index */
    if ((queue->front != -1 && (queue->front < 0 || queue->front >= MAX_QUEUE_SIZE)) ||
        (queue->rear  != -1 && (queue->rear  < 0 || queue->rear  >= MAX_QUEUE_SIZE))) {
        return false;
    }

    return true;
}

/* -------------------------------------------------------------------------
 * Initialise a newly allocated queue.
 * ------------------------------------------------------------------------- */
void queue_init(queue_t *queue)
{
    if (queue == NULL) {
        /* In production code you would log this condition or abort. */
        return;
    }

    queue->front = -1;
    queue->rear  = -1;
}

/* -------------------------------------------------------------------------
 * Is the queue full?
 * Returns:
 *   true  – queue is full
 *   false – queue is not full or the queue pointer is invalid
 * ------------------------------------------------------------------------- */
bool is_queue_full(const queue_t *queue)
{
    if (!queue_is_valid(queue)) {
        /* Defensive default: treat an invalid queue as “not full”. */
        return false;
    }

    /* When front == -1 the queue is empty, therefore it cannot be full. */
    if (queue->front == -1) {
        return false;
    }

    return ((queue->rear + 1) % MAX_QUEUE_SIZE) == queue->front;
}

/* -------------------------------------------------------------------------
 * Is the queue empty?
 * Returns:
 *   true  – queue is empty
 *   false – queue contains at least one element or the pointer is invalid
 * ------------------------------------------------------------------------- */
bool is_queue_empty(const queue_t *queue)
{
    if (!queue_is_valid(queue)) {
        /* Defensive default: treat an invalid queue as “empty”. */
        return true;
    }

    return (queue->front == -1 && queue->rear == -1);
}
