#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <errno.h>
#include <limits.h>

/* -------------------------------------------------------------------------
 * Global resources – keep them minimal and clearly owned.
 * ------------------------------------------------------------------------- */
static float *filtered_audio_buffer = NULL;
static const size_t SAMPLES_COUNT = SAMPLES;   /* SAMPLES must be a macro or const */

/* -------------------------------------------------------------------------
 * Helper: safe multiplication with overflow detection.
 * ------------------------------------------------------------------------- */
static int safe_mul_size_t(size_t a, size_t b, size_t *out)
{
    if (a == 0 || b == 0) {
        *out = 0;
        return 0;
    }
    if (a > SIZE_MAX / b) {
        return -1;          /* overflow */
    }
    *out = a * b;
    return 0;
}

/* -------------------------------------------------------------------------
 * SIGINT handler – performs only async‑signal‑safe actions.
 * ------------------------------------------------------------------------- */
static void sigint_handler(int signo)
{
    /* async‑signal‑safe: write to STDERR using write(2) */
    const char msg[] = "\nSIGINT received – cleaning up and exiting.\n";
    write(STDERR_FILENO, msg, sizeof(msg) - 1);

    /* Free the buffer if it was allocated – free() is async‑signal‑safe. */
    if (filtered_audio_buffer) {
        free(filtered_audio_buffer);
        filtered_audio_buffer = NULL;
    }

    _exit(EXIT_SUCCESS);   /* immediate, async‑signal‑safe termination */
}

/* -------------------------------------------------------------------------
 * Installation of a robust signal handler using sigaction().
 * ------------------------------------------------------------------------- */
static void install_sigint_handler(void)
{
    struct sigaction sa = {0};
    sa.sa_handler = sigint_handler;
    /* Block all signals while the handler runs to avoid re‑entrancy. */
    sigfillset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART;   /* restart interrupted syscalls when safe */

    if (sigaction(SIGINT, &sa, NULL) == -1) {
        perror("sigaction");
        exit(EXIT_FAILURE);
    }
}

/* -------------------------------------------------------------------------
 * Main allocation routine – includes overflow check and error handling.
 * ------------------------------------------------------------------------- */
static void allocate_filtered_buffer(void)
{
    size_t bytes_needed = 0;
    if (safe_mul_size_t(SAMPLES_COUNT, sizeof(float), &bytes_needed) != 0) {
        fprintf(stderr, "Requested allocation size overflows size_t.\n");
        exit(EXIT_FAILURE);
    }

    filtered_audio_buffer = malloc(bytes_needed);
    if (!filtered_audio_buffer) {
        perror("Failed to allocate filtered audio buffer");
        exit(EXIT_FAILURE);
    }

    /* Optional: zero‑initialize to avoid leaking uninitialized data. */
    memset(filtered_audio_buffer, 0, bytes_needed);
}

/* -------------------------------------------------------------------------
 * Application entry point – demonstrates proper resource lifecycle.
 * ------------------------------------------------------------------------- */
int main(void)
{
    install_sigint_handler();      /* Install robust handler first */
    allocate_filtered_buffer();    /* Allocate with safety checks */

    /* ... audio‑processing logic that uses filtered_audio_buffer ... */

    /* Normal shutdown path – clean up resources. */
    free(filtered_audio_buffer);
    filtered_audio_buffer = NULL;

    return EXIT_SUCCESS;
}
