    /* 2️⃣  Prepare hints for getaddrinfo – IPv4 or IPv6, TCP. */
    hints.ai_family   = AF_UNSPEC;      /* allow IPv4 or IPv6 */
    hints.ai_socktype = SOCK_STREAM;    /* TCP */
    hints.ai_flags    = AI_NUMERICSERV; /* port is numeric */

    rc = getaddrinfo(hostname, port_str, &hints, &res);
    if (rc != 0) {
        fprintf(stderr, "getaddrinfo: %s\n", gai_strerror(rc));
        return -1;
    }

    /* 3️⃣  Iterate over the returned address list until we succeed. */
    for (struct addrinfo *p = res; p != NULL; p = p->ai_next) {
        /* Create socket */
        sockfd = socket(p->ai_family, p->ai_socktype, p->ai_protocol);
        if (sockfd < 0) {
            /* Non‑fatal – try next address */
            continue;
        }

        /* Connect */
        if (connect(sockfd, p->ai_addr, p->ai_addrlen) == 0) {
            /* Success – break out of the loop */
            break;
        }

        /* Connect failed – clean up this socket and try next */
        close(sockfd);
        sockfd = -1;
    }

    /* 4️⃣  Clean up address info (no longer needed). */
    freeaddrinfo(res);

    if (sockfd < 0) {
        /* No address succeeded */
        fprintf(stderr, "Unable to connect to %s:%s\n", hostname, port_str);
        return -1;
    }

    /* 5️⃣  At this point `sockfd` is a valid, connected socket. */
    return sockfd;
}

