/* -------------------------------------------------------------------------
 * Queue data structure (example)
 * -------------------------------------------------------------------------
 * typedef struct {
 *     int   data[MAX_QUEUE_SIZE];
 *     int   front;      // index of the front element, -1 when empty
 *     int   rear;       // index of the rear element,  -1 when empty
 * } queue_t;
 *
 * The queue is initialized elsewhere with:
 *     queue->front = -1;
 *     queue->rear  = -1;
 * ------------------------------------------------------------------------- */

/**
 * @brief  Returns true if the queue is full.
 *
 * @param  queue  Pointer to the queue instance. May be NULL.
 *
 * @return true  when the queue cannot accept more elements.
 * @return false otherwise (including the case where @p queue is NULL).
 */
static inline bool is_queue_full(const queue_t *queue)
{
    /* Defensive programming: reject a NULL pointer immediately. */
    if (queue == NULL) {
        /* Optionally log the misuse for observability. */
        /* log_warning("is_queue_full called with NULL queue pointer"); */
        return false;               /* Treat as “not full” – safe fallback. */
    }

    /* The queue is full when advancing rear would collide with front. */
    return ((queue->rear + 1) % MAX_QUEUE_SIZE) == queue->front;
}

/**
 * @brief  Returns true if the queue is empty.
 *
 * @param  queue  Pointer to the queue instance. May be NULL.
 *
 * @return true  when the queue contains no elements.
 * @return false otherwise (including the case where @p queue is NULL).
 */
static inline bool is_queue_empty(const queue_t *queue)
{
    if (queue == NULL) {
        /* log_warning("is_queue_empty called with NULL queue pointer"); */
        return true;                /* Treat a missing queue as empty. */
    }

    /* Empty state is represented by both indices being -1. */
    return (queue->front == -1) && (queue->rear == -1);
}
