/*=== queue.c =============================================================*/
#include "queue.h"

/* -----------------------------------------------------------------------
 * Helper: safe modulo for positive indices (avoids undefined behaviour on
 * negative values). Because MAX_QUEUE_SIZE is a power of two we can use a
 * bit‑mask for efficiency, but the generic version is kept for clarity.
 * ----------------------------------------------------------------------- */
static inline int32_t wrap_index(int32_t idx)
{
    /* idx is guaranteed to be non‑negative when called */
    return idx % (int32_t)MAX_QUEUE_SIZE;
}

/* -----------------------------------------------------------------------
 * Initialise a queue instance.
 * ----------------------------------------------------------------------- */
queue_status_t queue_create(queue_t *queue)
{
    if (queue == NULL) {
        return QUEUE_ERR_NULL_PTR;
    }

    /* In debug builds we assert the invariant; in production we just set it */
    assert(queue != NULL);
    queue->front = -1;
    queue->rear  = -1;
    return QUEUE_OK;
}

/* -----------------------------------------------------------------------
 * Query helpers – they accept a const pointer and perform a NULL check.
 * ----------------------------------------------------------------------- */
bool queue_is_full(const queue_t *queue)
{
    if (queue == NULL) {
        /* Treat a NULL queue as “not full” – callers should have checked */
        return false;
    }
    /* When the queue is empty front == -1, rear == -1, so the expression
       correctly evaluates to false. */
    return (wrap_index(queue->rear + 1) == queue->front);
}

bool queue_is_empty(const queue_t *queue)
{
    if (queue == NULL) {
        return true;   /* A NULL queue cannot contain elements */
    }
    return (queue->front == -1);
}

/* -----------------------------------------------------------------------
 * Enqueue – adds an element if there is space.
 * ----------------------------------------------------------------------- */
queue_status_t queue_enqueue(queue_t *queue, int32_t value)
{
    if (queue == NULL) {
        return QUEUE_ERR_NULL_PTR;
    }

    if (queue_is_full(queue)) {
        return QUEUE_ERR_FULL;
    }

    if (queue_is_empty(queue)) {
        /* First element – initialise both indices */
        queue->front = 0;
        queue->rear  = 0;
    } else {
        queue->rear = wrap_index(queue->rear + 1);
    }

    queue->data[queue->rear] = value;
    return QUEUE_OK;
}

/* -----------------------------------------------------------------------
 * Dequeue – removes the oldest element.
 * ----------------------------------------------------------------------- */
queue_status_t queue_dequeue(queue_t *queue, int32_t *out_value)
{
    if (queue == NULL || out_value == NULL) {
        return QUEUE_ERR_NULL_PTR;
    }

    if (queue_is_empty(queue)) {
        return QUEUE_ERR_EMPTY;
    }

    *out_value = queue->data[queue->front];

    if (queue->front == queue->rear) {
        /* Queue becomes empty after this removal */
        queue->front = -1;
        queue->rear  = -1;
    } else {
        queue->front = wrap_index(queue->front + 1);
    }

    return QUEUE_OK;
}
