static int safe_mul_size_t(size_t a, size_t b, size_t *out)
{
    if (a == 0 || b == 0) {
        *out = 0;
        return 1;
    }
    if (a > SIZE_MAX / b) {      /* overflow */
        return 0;
    }
    *out = a * b;
    return 1;
}

/* --------------------------------------------------------------------- */
