    grid_t *grid = malloc(sizeof(*grid));
    if (!grid) {
        fprintf(stderr, "Failed to allocate grid structure.\n");
        return EXIT_FAILURE;
    }

    grid->width  = WIDTH;
    grid->height = HEIGHT;
    grid->grid   = NULL;                 /* initialise for safe cleanup */

