  - Range‑checked: validates day (1‑31) and year (1900‑2100).
  - No side‑effects: does not modify the caller's string beyond tokenisation.
=====================================================================*/

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>
#include <errno.h>

/* Helper: verify that a string consists only of decimal digits */
static int is_all_digits(const char *s)
{
    if (s == NULL || *s == '\0')
        return 0;
    for (const char *p = s; *p != '\0'; ++p) {
        if (!isdigit((unsigned char)*p))
            return 0;
    }
    return 1;
}

/*-------------------------------------------------
  extract_day
  Input:  date_string – a mutable copy of the original date,
          e.g. "12/31/2023". The function will tokenize this copy.
  Output: *day_out receives the day (1‑31) on success.
  Return: 0 on success, non‑zero error code on failure.
-------------------------------------------------*/
int extract_day(char *date_string, int *day_out)
{
    if (date_string == NULL || day_out == NULL)
        return EINVAL;               /* invalid arguments */

    char *saveptr = NULL;
    char *token   = strtok_r(date_string, "/", &saveptr);   /* month – ignored */
    if (token == NULL)
        return EINVAL;               /* malformed date */

    token = strtok_r(NULL, "/", &saveptr);                  /* day */
    if (token == NULL)
        return EINVAL;               /* missing day token */

    if (!is_all_digits(token))
        return EINVAL;               /* non‑numeric day */

    long day = strtol(token, NULL, 10);
    if (day < 1 || day > 31)
        return ERANGE;               /* day out of realistic range */

    *day_out = (int)day;
    return 0;                        /* success */
}

/*-------------------------------------------------
  extract_year
  Input:  date_string – a mutable copy of the original date,
          e.g. "12/31/2023". The function will tokenize this copy.
  Output: *year_out receives the year (1900‑2100) on success.
  Return: 0 on success, non‑zero error code on failure.
-------------------------------------------------*/
int extract_year(char *date_string, int *year_out)
{
    if (date_string == NULL || year_out == NULL)
        return EINVAL;

    char *saveptr = NULL;
    char *token   = strtok_r(date_string, "/", &saveptr);   /* month – ignored */
    if (token == NULL)
        return EINVAL;

    token = strtok_r(NULL, "/", &saveptr);                  /* day – ignored */
    if (token == NULL)
        return EINVAL;

    token = strtok_r(NULL, "/", &saveptr);                  /* year */
    if (token == NULL)
        return EINVAL;

    if (!is_all_digits(token))
        return EINVAL;

    long year = strtol(token, NULL, 10);
    if (year < 1900 || year > 2100)
        return ERANGE;

    *year_out = (int)year;
    return 0;
}

