/* Helper: convert a string to a bounded integer */
static int parse_int(const char *s, int *out, int min, int max) {
    char *endptr = NULL;
    long val;

    errno = 0;
    val = strtol(s, &endptr, 10);

    /* Detect conversion errors */
    if (errno != 0 || endptr == s || *endptr != '\0')
        return -1;

    if (val < min || val > max)
        return -1;

    *out = (int)val;
    return 0;
}

/* Prompt the user and safely read a single option character */
