/* -------------------------------------------------------------
 *  Secure grid allocation and initialisation
 * ------------------------------------------------------------- */
#include <stdio.h>
#include <stdlib.h>
#include <stddef.h>
#include <stdint.h>
#include <pthread.h>
#include <errno.h>
#include <limits.h>

#define CELL_SIZE   1U               /* logical size – not used for indexing */
#define MAX_THREADS 10U

/* -----------------------------------------------------------------
 *  Types
 * ----------------------------------------------------------------- */
typedef struct {
    unsigned int x;
    unsigned int y;
    int          alive;
} cell_t;

typedef struct {
    size_t   width;   /* number of columns  */
    size_t   height;  /* number of rows     */
    cell_t **grid;    /* pointer to an array of row pointers */
} grid_t;

/* -----------------------------------------------------------------
 *  Helper macros / functions
 * ----------------------------------------------------------------- */

/* Safe multiplication that detects overflow (C23 `mul_overflow` fallback). */
static inline int safe_mul_size_t(size_t a, size_t b, size_t *out)
{
#if defined(__STDC_VERSION__) && __STDC_VERSION__ >= 202000L
    return mul_overflow(a, b, out);
#else
    if (a == 0 || b == 0) {
        *out = 0;
        return 0;
    }
    if (a > SIZE_MAX / b) {
        return 1;               /* overflow */
    }
    *out = a * b;
    return 0;
#endif
}

/* Index a cell in a flat array of pointers (row‑major order). */
#define GRID_IDX(g, i, j) ((g)->grid[(i) * (g)->width + (j)])

static void free_grid(grid_t *g)
{
    if (!g) return;

    if (g->grid) {
        for (size_t i = 0; i < g->height; ++i) {
            free(g->grid[i]);          /* each row may be NULL */
        }
        free(g->grid);
    }
}

/* -----------------------------------------------------------------
 *  Allocation routine – returns 0 on success, non‑zero on error.
 * ----------------------------------------------------------------- */
static int allocate_grid(grid_t *g, size_t width, size_t height)
{
    if (!g) return EINVAL;

    g->width  = width;
    g->height = height;
    g->grid   = NULL;

    /* -------------------------------------------------------------
     *  1️⃣ Allocate the array of row pointers (height rows)
     * ------------------------------------------------------------- */
    size_t rows_bytes;
    if (safe_mul_size_t(height, sizeof *g->grid, &rows_bytes))
        return ENOMEM;                     /* overflow → treat as OOM */

    g->grid = malloc(rows_bytes);
    if (!g->grid) return ENOMEM;

    /* Initialise the row‑pointer array to NULL so the clean‑up loop is safe */
    for (size_t i = 0; i < height; ++i)
        g->grid[i] = NULL;

    /* -------------------------------------------------------------
     *  2️⃣ Allocate each row (width cells per row)
     * ------------------------------------------------------------- */
    for (size_t i = 0; i < height; ++i) {
        size_t row_bytes;
        if (safe_mul_size_t(width, sizeof *g->grid[i], &row_bytes)) {
            free_grid(g);
            return ENOMEM;
        }

        g->grid[i] = malloc(row_bytes);
        if (!g->grid[i]) {
            free_grid(g);
            return ENOMEM;
        }

        /* ---------------------------------------------------------
         *  3️⃣ Initialise the cells of the row
         * --------------------------------------------------------- */
        for (size_t j = 0; j < width; ++j) {
            cell_t *c = &g->grid[i][j];
            c->x = (unsigned int)i * CELL_SIZE;
            c->y = (unsigned int)j * CELL_SIZE;
            c->alive = 1;
        }
    }

    return 0;   /* success */
}

/* -----------------------------------------------------------------
 *  Example usage (including thread creation)
 * ----------------------------------------------------------------- */
int main(void)
{
    grid_t my_grid = {0};

    const size_t w = 20, h = 15;          /* example dimensions */
    int rc = allocate_grid(&my_grid, w, h);
    if (rc) {
        fprintf(stderr, "Failed to allocate grid: %s\n", strerror(rc));
        return EXIT_FAILURE;
    }

    /* -------------------------------------------------------------
     *  Thread pool – robust creation with error handling
     * ------------------------------------------------------------- */
    pthread_t threads[MAX_THREADS];
    for (size_t i = 0; i < MAX_THREADS; ++i) {
        rc = pthread_create(&threads[i], NULL, /* thread start routine */ NULL, NULL);
        if (rc) {
            fprintf(stderr, "pthread_create failed for thread %zu: %s\n",
                    i, strerror(rc));
            /* Optional: join already‑started threads before aborting */
            for (size_t j = 0; j < i; ++j)
                pthread_join(threads[j], NULL);
            free_grid(&my_grid);
            return EXIT_FAILURE;
        }
    }

    /* ... do work with the grid and threads ... */

    /* Clean‑up */
    for (size_t i = 0; i < MAX_THREADS; ++i)
        pthread_join(threads[i], NULL);
    free_grid(&my_grid);
    return EXIT_SUCCESS;
}
```

### Why This Fix Is Secure

1. **Null‑pointer safety** – Every `malloc` result is verified before use. If any allocation fails, the function immediately frees everything that was successfully allocated and returns an error code. No dereference of a `NULL` pointer can occur.

2. **Correct memory layout** – The grid is stored as an array of *row pointers* (`cell_t **grid`). Each row is a contiguous block of `cell_t` objects (`width` elements). Indexing uses `grid[i][j]`, which is both readable and guaranteed to stay inside the allocated memory.

3. **Overflow‑aware size calculations** – `safe_mul_size_t` prevents integer overflow when computing the total number of bytes to allocate. This eliminates the classic *malloc overflow* CWE‑680.

4. **No unnecessary casts** – Assigning the result of `malloc` directly to the target pointer type avoids the classic CWE‑476 “NULL pointer dereference” pattern that can be introduced by incorrect casts.

5. **Explicit constants & limits** – `MAX_THREADS` replaces the magic number `10`. This makes future changes straightforward and self‑documenting.

6. **Thread‑creation error handling** – Each `pthread_create` call is checked. On failure, already‑started threads are joined, resources are released, and the program exits cleanly.

7. **Resource clean‑up** – `free_grid` centralises deallocation, guaranteeing that every successful allocation is paired with a corresponding `free`, even when an intermediate step fails.

8. **Static‑analysis friendly** – Using `sizeof *ptr` and clear loop bounds helps tools such as *Clang‑Static‑Analyzer*, *Coverity*, and *CodeQL* to verify the absence of out‑of‑bounds accesses and memory leaks.

