    }
    if (val < 1 || val > 65535) {      /* valid TCP/UDP port range */
        return -1;
    }
    *out_port = (uint16_t)val;
    return 0;
}

/* -------------------------------------------------------------
 * Resolve `host` (IPv4 or IPv6) and fill a sockaddr_storage.
 * Returns 0 on success, -1 on failure.
 * ------------------------------------------------------------- */
static int resolve_host(const char *host,
                        const uint16_t port,
                        struct sockaddr_storage *addr,
                        socklen_t *addrlen)
{
    struct addrinfo hints = {0}, *res = NULL;
    char port_buf[6];   /* max "65535"+'\0' */

    if (host == NULL || addr == NULL || addrlen == NULL) {
        return -1;
    }

    snprintf(port_buf, sizeof(port_buf), "%u", port);

    hints.ai_family   = AF_UNSPEC;      /* allow IPv4 or IPv6 */
    hints.ai_socktype = SOCK_STREAM;    /* TCP */
    hints.ai_flags    = AI_NUMERICSERV; /* port is numeric */

    int rc = getaddrinfo(host, port_buf, &hints, &res);
    if (rc != 0) {
        return -1;
    }

    /* Use the first result */
    memcpy(addr, res->ai_addr, res->ai_addrlen);
    *addrlen = (socklen_t)res->ai_addrlen;

    freeaddrinfo(res);
    return 0;
}

