#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <limits.h>

#define MAX_WORDS      1024          /* maximum entries we can store */
#define MAX_WORD_LEN   64            /* maximum length of a word (including '\0') */
#define LINE_BUF_SIZE  (MAX_WORD_LEN + 32)   /* enough for word + integer + whitespace */

typedef struct {
    char word[MAX_WORD_LEN];
    int  class;
} word_entry_t;

/* --------------------------------------------------------------------- */
/* Helper: safely convert a string to int with overflow detection          */
static int safe_str_to_int(const char *s, int *out)
{
    char *endptr = NULL;
    long  val   = strtol(s, &endptr, 10);

    if (endptr == s || *endptr != '\0')          /* no digits or extra chars */
        return -1;
    if ((errno == ERANGE && (val == LONG_MAX || val == LONG_MIN)) ||
        val > INT_MAX || val < INT_MIN)         /* overflow/underflow */
        return -1;

    *out = (int)val;
    return 0;
}

/* --------------------------------------------------------------------- */
void load_words(const char *filename, word_entry_t *words, size_t max_words,
                size_t *out_num_words)
{
    FILE *file = fopen(filename, "r");
    if (!file) {
        fprintf(stderr, "Error: Unable to open words file \"%s\".\n", filename);
        exit(EXIT_FAILURE);
    }

    char line[LINE_BUF_SIZE];
    size_t count = 0;

    while (fgets(line, sizeof(line), file) != NULL) {
        /* Trim trailing newline (optional, but tidy) */
        line[strcspn(line, "\r\n")] = '\0';

        /* Split the line into two tokens: word and class */
        char word_buf[MAX_WORD_LEN];
        char class_buf[32];          /* enough for any 32‑bit integer string */

        /* Use sscanf with width specifiers to avoid overruns */
        int scanned = sscanf(line, "%63s %31s", word_buf, class_buf);
        if (scanned != 2) {
            fprintf(stderr,
                    "Warning: malformed line %zu – expected '<word> <class>'. Skipping.\n",
                    count + 1);
            continue;   /* skip this line but keep processing the rest */
        }

        /* Verify we still have space for another entry */
        if (count >= max_words) {
            fprintf(stderr,
                    "Error: exceeded maximum number of words (%zu). Stopping load.\n",
                    max_words);
            break;
        }

        /* Copy the word safely (already limited by %63s) */
        strncpy(words[count].word, word_buf, MAX_WORD_LEN);
        words[count].word[MAX_WORD_LEN - 1] = '\0';   /* guarantee NUL‑termination */

        /* Convert class string to int with full validation */
        if (safe_str_to_int(class_buf, &words[count].class) != 0) {
            fprintf(stderr,
                    "Warning: invalid class value on line %zu. Skipping entry.\n",
                    count + 1);
            continue;
        }

        ++count;
    }

    fclose(file);
    *out_num_words = count;
}

/* --------------------------------------------------------------------- */
int main(void)
{
    word_entry_t words[MAX_WORDS];
    size_t       num_words = 0;

    load_words("words.txt", words, MAX_WORDS, &num_words);

    printf("Successfully loaded %zu word(s).\n", num_words);
    /* … further processing … */
    return 0;
}
