int insertAtEnd(LinkedList *list, int value)
{
    /* 1️⃣ Validate the list pointer */
    if (list == NULL) {
        /* Optional: log the error for observability */
        fprintf(stderr, "insertAtEnd error: list pointer is NULL\n");
        return 1;
    }

    /* 2️⃣ Allocate the new node safely */
    Node *newNode = createNode(value);
    if (newNode == NULL) {
        fprintf(stderr, "insertAtEnd error: memory allocation for new node failed\n");
        return 2;
    }

    /* 3️⃣ Insert the node */
    if (isEmpty(list)) {
        /* Empty list – new node becomes the head */
        list->head = newNode;
    } else {
        /* Non‑empty list – walk to the tail safely */
        Node *current = list->head;
        while (current->next != NULL) {
            current = current->next;
        }
        /* At this point `current` is the last node; link the new node */
        current->next = newNode;
    }

    /* 4️⃣ Success */
    return 0;
}
