#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>

#define MAX_WORD_LEN   64          /* Adjust to the longest expected word + 1 */
#define MAX_VOCAB_SIZE 1024        /* Adjust to the maximum number of entries */

/* Structure that holds one translation pair */
typedef struct {
    char english[MAX_WORD_LEN];
    char alien[MAX_WORD_LEN];
} vocab_entry;

/* Global (or appropriately scoped) storage */
static vocab_entry vocabulary[MAX_VOCAB_SIZE];
static size_t      vocabularySize = 0;

/* --------------------------------------------------------------------- */
/* Helper: safely read a line from the file and parse two tokens.        */
/* Returns 0 on success, non‑zero on EOF or parse error.                 */
/* --------------------------------------------------------------------- */
static int read_vocab_line(FILE *fp)
{
    char line[2 * MAX_WORD_LEN + 16];   /* generous buffer for the whole line */
    char *tok_english, *tok_alien;

    /* 1️⃣ Read a full line – fgets guarantees null‑termination and respects the buffer size */
    if (fgets(line, sizeof(line), fp) == NULL) {
        return (feof(fp) ? 0 : -1);   /* EOF → normal termination, otherwise error */
    }

    /* 2️⃣ Strip trailing newline (optional, but tidy) */
    line[strcspn(line, "\r\n")] = '\0';

    /* 3️⃣ Tokenise safely – strtok_r is re‑entrant and does not write beyond the line buffer */
    tok_english = strtok_r(line, " \t", &line);
    if (tok_english == NULL) return -1;   /* malformed line */

    tok_alien = strtok_r(NULL, " \t", &line);
    if (tok_alien == NULL) return -1;     /* malformed line */

    /* 4️⃣ Verify length before copying – prevents buffer overflow (CWE‑120) */
    if (strlen(tok_english) >= MAX_WORD_LEN || strlen(tok_alien) >= MAX_WORD_LEN) {
        fprintf(stderr,
                "Warning: Truncating over‑long word (english='%s', alien='%s')\n",
                tok_english, tok_alien);
        /* Truncate safely */
        strncpy(vocabulary[vocabularySize].english, tok_english, MAX_WORD_LEN - 1);
        strncpy(vocabulary[vocabularySize].alien,   tok_alien,   MAX_WORD_LEN - 1);
    } else {
        /* Exact copy – safe because we already checked the lengths */
        strcpy(vocabulary[vocabularySize].english, tok_english);
        strcpy(vocabulary[vocabularySize].alien,   tok_alien);
    }

    ++vocabularySize;
    return 0;
}

/* --------------------------------------------------------------------- */
