/*=====================================================================
  Secure month‑extraction helper
  --------------------------------------------------------------------
  extract_month:
      - Takes a NUL‑terminated date string in the form "MM/DD/YYYY".
      - Returns a newly allocated string containing the month component
        (e.g., "04") or NULL on error.
      - The caller is responsible for freeing the returned pointer.
=====================================================================*/

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>

/* Maximum expected length of a date string.
   Adjust if your format can be longer (e.g., include leading zeros). */
#define DATE_MAX_LEN  32

/**
 * @brief Safely extracts the month component from a date string.
 *
 * @param date_string  NUL‑terminated input string (must not be NULL).
 * @return char*       Dynamically allocated month string, or NULL on error.
 *
 * @note The caller must free() the returned pointer.
 */
char *extract_month(const char *date_string)
{
    /*--------------------------------------------------------------
      1. Validate input
    --------------------------------------------------------------*/
    if (date_string == NULL) {
        errno = EINVAL;
        return NULL;
    }

    /*--------------------------------------------------------------
      2. Make a bounded copy of the input to avoid modifying the caller’s buffer.
    --------------------------------------------------------------*/
    char buffer[DATE_MAX_LEN];
    size_t copy_len = strnlen(date_string, DATE_MAX_LEN - 1);
    if (copy_len == DATE_MAX_LEN - 1 && date_string[copy_len] != '\0') {
        /* Input exceeds our safe buffer size */
        errno = ENAMETOOLONG;
        return NULL;
    }
    memcpy(buffer, date_string, copy_len);
    buffer[copy_len] = '\0';

    /*--------------------------------------------------------------
      3. Tokenise safely using strtok_r (re‑entrant, thread‑safe)
    --------------------------------------------------------------*/
    char *saveptr = NULL;
    char *token   = strtok_r(buffer, "/", &saveptr);
    if (token == NULL) {
        errno = EINVAL;          /* No token found – malformed date */
        return NULL;
    }

    /*--------------------------------------------------------------
      4. Allocate a clean copy for the month string.
          - Use strdup if available, otherwise allocate + memcpy.
          - Verify allocation succeeded.
    --------------------------------------------------------------*/
    char *month = strdup(token);
    if (month == NULL) {
        /* Propagate allocation failure */
        errno = ENOMEM;
        return NULL;
    }

    /*--------------------------------------------------------------
      5. Return the newly allocated month string.
    --------------------------------------------------------------*/
    return month;
}

/*=====================================================================
  Example usage (demonstrates proper memory handling)
=====================================================================*/
int main(void)
{
    const char *date = "04/15/2023";

    char *month = extract_month(date);
    if (month == NULL) {
        perror("extract_month failed");
        return EXIT_FAILURE;
    }

    printf("Parsed month: %s\n", month);
    free(month);   /* <-- IMPORTANT: release the allocation */

    return EXIT_SUCCESS;
}
```

