#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <limits.h>

/* ----------------------------------------------------------------------
 *  Data structure representing a calendar date.
 * ---------------------------------------------------------------------- */
typedef struct {
    int day;
    int month;
    int year;
} Date;

/* ----------------------------------------------------------------------
 *  Extract the year component from a date string of the form "DD/MM/YYYY".
 *
 *  Parameters
 *  ----------
 *  date_string : const char *
 *      Null‑terminated string containing the full date. Must not be NULL.
 *
 *  Returns
 *  -------
 *  int
 *      The parsed year on success, or -1 on any error (NULL input,
 *      malformed string, non‑numeric year, overflow, etc.).
 * ---------------------------------------------------------------------- */
int extract_year(const char *date_string)
{
    if (date_string == NULL) {
        /* Input validation failure – avoid dereferencing NULL. */
        return -1;
    }

    /* Make a mutable copy because strtok_r modifies the buffer. */
    char *buf = strdup(date_string);
    if (buf == NULL) {
        /* Allocation failure – treat as error. */
        return -1;
    }

    char *saveptr = NULL;
    /* Token 1: day (ignored here) */
    char *token = strtok_r(buf, "/", &saveptr);
    if (token == NULL) {
        free(buf);
        return -1;
    }

    /* Token 2: month (ignored here) */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) {
        free(buf);
        return -1;
    }

    /* Token 3: year – this is what we need */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) {
        free(buf);
        return -1;
    }

    /* Convert the year safely with strtol */
    errno = 0;
    char *endptr = NULL;
    long year_long = strtol(token, &endptr, 10);

    /* Detect conversion errors */
    if (errno != 0 || endptr == token || *endptr != '\0' ||
        year_long < INT_MIN || year_long > INT_MAX) {
        free(buf);
        return -1;
    }

    free(buf);
    return (int)year_long;
}

/* ----------------------------------------------------------------------
 *  Parse a full date string "DD/MM/YYYY" into a Date structure.
 *
 *  Returns
 *  -------
 *  Date *
 *      Pointer to a newly allocated Date on success, or NULL on error.
 *      The caller is responsible for freeing the returned object.
 * ---------------------------------------------------------------------- */
Date *parse_date(const char *date_string)
{
    if (date_string == NULL) {
        return NULL;
    }

    /* Duplicate the string because strtok_r will modify it. */
    char *buf = strdup(date_string);
    if (buf == NULL) {
        return NULL;
    }

    char *saveptr = NULL;
    char *token = NULL;
    Date *result = calloc(1, sizeof(Date));
    if (result == NULL) {
        free(buf);
        return NULL;
    }

    /* Day */
    token = strtok_r(buf, "/", &saveptr);
    if (token == NULL) goto fail;
    errno = 0;
    long day = strtol(token, &saveptr, 10);
    if (errno != 0 || saveptr == token || *saveptr != '\0' ||
        day < 1 || day > 31) {
        goto fail;
    }
    result->day = (int)day;

    /* Month */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) goto fail;
    errno = 0;
    long month = strtol(token, &saveptr, 10);
    if (errno != 0 || saveptr == token || *saveptr != '\0' ||
        month < 1 || month > 12) {
        goto fail;
    }
    result->month = (int)month;

    /* Year – reuse the safe extraction logic */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) goto fail;
    errno = 0;
    long year = strtol(token, &saveptr, 10);
    if (errno != 0 || saveptr == token || *saveptr != '\0' ||
        year < INT_MIN || year > INT_MAX) {
        goto fail;
    }
    result->year = (int)year;

    free(buf);
    return result;

fail:
    free(buf);
    free(result);
    return NULL;
