    room *r = (room *)malloc(sizeof(room));
    if (r == NULL) {
        /* Out‑of‑memory – propagate failure to the caller */
        return NULL;
    }

    /* Initialise fields */
    safe_strncpy(r->name, name, sizeof(r->name));
    r->num_devices = 0;
    /* Zero‑initialise the device array to avoid leaking uninitialised data */
    memset(r->devices, 0, sizeof(r->devices));

    return r;
}

