static void *xmalloc(size_t size)
{
    void *p = malloc(size);
    if (p == NULL) {
        fprintf(stderr, "Fatal error: malloc(%zu) failed: %s\n",
                size, strerror(errno));
        exit(EXIT_FAILURE);
    }
    return p;
}

/* Helper: safely copy a filename into a fixed‑size buffer */
static void build_output_name(char *out_buf, size_t out_buf_len,
                              const char *prefix, const char *src)
{
    /* snprintf guarantees null‑termination and never writes past out_buf_len */
    int n = snprintf(out_buf, out_buf_len, "%s%s", prefix, src);
    if (n < 0 || (size_t)n >= out_buf_len) {
        fprintf(stderr, "Fatal error: output filename too long (max %zu bytes)\n",
                out_buf_len - 1);
        exit(EXIT_FAILURE);
    }
}

/* --------------------------------------------------------------------- */
/* Example usage – encrypt a file buffer with a repeating XOR key           */
/* --------------------------------------------------------------------- */
void encrypt_and_write(const char *filename,
                       const unsigned char *plaintext,
                       size_t file_size,
                       const unsigned char *xor_key,
                       size_t key_len)
{
    /* ----------------------------------------------------------------- */
    /* 1️⃣ Validate caller‑supplied pointers                               */
    /* ----------------------------------------------------------------- */
    if (filename == NULL || plaintext == NULL ||
        xor_key == NULL || key_len == 0) {
        fprintf(stderr, "Invalid arguments to encrypt_and_write()\n");
        return;
    }

    /* ----------------------------------------------------------------- */
    /* 2️⃣ Allocate ciphertext; abort if allocation fails                  */
    /* ----------------------------------------------------------------- */
    unsigned char *ciphertext = xmalloc(file_size + 1);   /* +1 for NUL terminator */

    /* ----------------------------------------------------------------- */
    /* 3️⃣ Perform XOR – protect against out‑of‑bounds key access          */
    /* ----------------------------------------------------------------- */
    for (size_t i = 0; i < file_size; ++i) {
        ciphertext[i] = plaintext[i] ^ xor_key[i % key_len];
    }
    ciphertext[file_size] = '\0';   /* optional NUL‑termination for debugging */

    /* ----------------------------------------------------------------- */
    /* 4️⃣ Build a safe output filename                                    */
    /* ----------------------------------------------------------------- */
    char new_filename[MAX_FILENAME_LEN];
    build_output_name(new_filename, sizeof(new_filename),
                      "surreal_", filename);

    /* ----------------------------------------------------------------- */
    /* 5️⃣ Open the output file safely                                      */
    /* ----------------------------------------------------------------- */
    FILE *file_out = fopen(new_filename, "wb");
    if (file_out == NULL) {
        fprintf(stderr, "Failed to open %s for writing: %s\n",
                new_filename, strerror(errno));
        free(ciphertext);
        return;
    }

    /* ----------------------------------------------------------------- */
    /* 6️⃣ Write the ciphertext atomically                                 */
    /* ----------------------------------------------------------------- */
    size_t written = fwrite(ciphertext, 1, file_size, file_out);
    if (written != file_size) {
        fprintf(stderr, "Partial write to %s (expected %zu, wrote %zu)\n",
                new_filename, file_size, written);
        /* Continue to close the file – we already reported the error */
    }

    /* ----------------------------------------------------------------- */
    /* 7️⃣ Clean up resources                                              */
    /* ----------------------------------------------------------------- */
    fclose(file_out);
    free(ciphertext);
}
