/* ------------------------------------------------------------------- */
bool safe_mul_uint32(uint32_t a, uint32_t b, uint32_t *out)
{
    if (a == 0 || b == 0) {
        *out = 0;
        return true;
    }
    if (a > UINT_MAX / b) {
        return false;               // overflow would occur
    }
    *out = a * b;
    return true;
