{
    /* A valid IPv4 mask consists of a contiguous block of 1‑bits
       followed by only 0‑bits (e.g., 0xFFFFFF00). */
    if (mask == 0) return false;
    uint32_t inverted = ~mask;
    return (inverted & (inverted + 1)) == 0;
}
