* **Use `size_t` for sizes** to avoid signed‑integer‑related bugs.  
* **Zero‑out freed memory** (optional but helps mitigate use‑after‑free).  
* **Avoid double‑free** by resetting pointers after `free`.  
* **Make the API robust to `NULL` arguments** – the caller can safely pass a `NULL` diary to `diary_free` without crashing.

```c
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <stdio.h>

typedef struct {
    char *title;
    char *body;
} DiaryEntry;

typedef struct {
    DiaryEntry *entries;   /* dynamically allocated array */
    size_t      num_entries;
    size_t      capacity;  /* allocated slots in entries */
} Diary;

/* --------------------------------------------------------------------- */
/* Helper: safely free a string and null‑out the pointer */
static void safe_str_free(char **p)
{
    if (p && *p) {
        free(*p);
        *p = NULL;
    }
}

/* --------------------------------------------------------------------- */
/* Securely release a Diary instance.  Accepts a NULL pointer safely.   */
void diary_free(Diary *diary)
{
    if (diary == NULL) {
        return;                     /* nothing to do */
    }

    for (size_t i = 0; i < diary->num_entries; ++i) {
        safe_str_free(&diary->entries[i].title);
        safe_str_free(&diary->entries[i].body);
    }

    safe_str_free((char **)&diary->entries);   /* free the array itself */
    free(diary);                               /* finally free the struct */
}

/* --------------------------------------------------------------------- */
/* Internal: grow the entries array safely. Returns 0 on success, -1 on error */
static int diary_grow(Diary *diary)
{
    const size_t MAX_CAPACITY = SIZE_MAX / sizeof(DiaryEntry);
    size_t new_cap;

    if (diary->capacity == 0) {
        new_cap = 4;                     /* initial allocation */
    } else {
        /* Detect overflow before doubling */
        if (diary->capacity > MAX_CAPACITY / 2) {
            return -1;                   /* would overflow */
        }
        new_cap = diary->capacity * 2;
    }

    DiaryEntry *tmp = realloc(diary->entries, new_cap * sizeof(DiaryEntry));
    if (tmp == NULL) {
        return -1;                       /* allocation failed */
    }

    /* Zero‑initialize the newly allocated slots */
    memset(tmp + diary->capacity, 0, (new_cap - diary->capacity) * sizeof(DiaryEntry));

    diary->entries  = tmp;
    diary->capacity = new_cap;
    return 0;
}

/* --------------------------------------------------------------------- */
/* Securely add a new entry. Returns 0 on success, -1 on failure.       */
int diary_add_entry(Diary *diary, const char *title, const char *body)
{
    /* Defensive programming – reject invalid arguments */
    if (diary == NULL || title == NULL || body == NULL) {
        return -1;
    }

    /* Grow the array if needed */
    if (diary->num_entries == diary->capacity) {
        if (diary_grow(diary) != 0) {
            return -1;   /* cannot allocate more space */
        }
    }

    /* Duplicate strings safely; abort if any allocation fails */
    char *title_dup = strdup(title);
    char *body_dup  = strdup(body);
    if (title_dup == NULL || body_dup == NULL) {
        safe_str_free(&title_dup);
        safe_str_free(&body_dup);
        return -1;
    }

    /* Store the new entry */
    DiaryEntry *e = &diary->entries[diary->num_entries];
    e->title = title_dup;
    e->body  = body_dup;

    diary->num_entries++;
    return 0;
}

/* --------------------------------------------------------------------- */
/* Optional: create a new empty Diary (caller must free with diary_free) */
Diary *diary_create(void)
{
    Diary *d = calloc(1, sizeof(Diary));
    if (d == NULL) {
        return NULL;
    }
    /* capacity starts at 0; diary_grow will allocate the first block */
    return d;
}
