#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <errno.h>

#define WIDTH        100U          /* example dimensions – replace with real values */
#define HEIGHT       100U
#define CELL_SIZE    1U            /* logical size of a cell – not used for pointer math */

/* ---------------------------------------------------------------------------
 * Data structures
 * --------------------------------------------------------------------------- */
typedef struct {
    unsigned int x;
    unsigned int y;
    int          alive;
} cell_t;

typedef struct {
    unsigned int width;   /* number of columns  */
    unsigned int height;  /* number of rows     */
    cell_t    **grid;    /* flat array of cell_t* of size width*height */
} grid_t;

/* ---------------------------------------------------------------------------
 * Helper: safe multiplication with overflow detection
 * --------------------------------------------------------------------------- */
static bool safe_mul_u32(uint32_t a, uint32_t b, uint32_t *out)
{
    uint64_t prod = (uint64_t)a * (uint64_t)b;
    if (prod > UINT32_MAX) {
        return false;
    }
    *out = (uint32_t)prod;
    return true;
}

/* ---------------------------------------------------------------------------
 * Allocate and initialise a grid
 * --------------------------------------------------------------------------- */
static int grid_init(grid_t *g, uint32_t width, uint32_t height)
{
    if (!g) {
        return EINVAL;
    }

    /* -----------------------------------------------------------------------
     * Validate dimensions – avoid zero‑size or overflow allocations
     * ----------------------------------------------------------------------- */
    if (width == 0 || height == 0) {
        return EINVAL;
    }

    uint32_t cell_cnt;
    if (!safe_mul_u32(width, height, &cell_cnt)) {
        return EOVERFLOW;               /* dimensions would overflow */
    }

    g->width  = width;
    g->height = height;

    /* -----------------------------------------------------------------------
     * Allocate the flat array of pointers (one pointer per cell)
     * ----------------------------------------------------------------------- */
    g->grid = calloc((size_t)cell_cnt, sizeof(cell_t *));
    if (!g->grid) {
        return ENOMEM;
    }

    /* -----------------------------------------------------------------------
     * Allocate each cell and initialise it
     * ----------------------------------------------------------------------- */
    for (uint32_t i = 0; i < width; ++i) {
        for (uint32_t j = 0; j < height; ++j) {
            size_t idx = (size_t)i * height + j;   /* correct linear index */

            cell_t *c = malloc(sizeof(cell_t));
            if (!c) {
                /* -------------------------------------------------------------
                 * On any allocation failure, unwind everything we have allocated
                 * ------------------------------------------------------------- */
                for (size_t k = 0; k < idx; ++k) {
                    free(g->grid[k]);
                }
                free(g->grid);
                g->grid = NULL;
                return ENOMEM;
            }

            c->x     = i * CELL_SIZE;
            c->y     = j * CELL_SIZE;
            c->alive = 1;

            g->grid[idx] = c;
        }
    }

    return 0;   /* success */
}

/* ---------------------------------------------------------------------------
 * Clean‑up helper – frees every cell and the pointer array
 * --------------------------------------------------------------------------- */
static void grid_destroy(grid_t *g)
{
    if (!g || !g->grid) {
        return;
    }

    uint32_t total = g->width * g->height;
    for (uint32_t i = 0; i < total; ++i) {
        free(g->grid[i]);
    }
    free(g->grid);
    g->grid = NULL;
}

