        return -1;        /* Propagate the error to the caller */
    }

    /* -----------------------------------------------------------------
     * ... perform work with `buffer` here ...
     * ----------------------------------------------------------------- */

    /* 2️⃣ Release the buffer safely. */
    safe_free((void **)&buffer);

    /* At this point `buffer` is guaranteed to be NULL, so any accidental
     * dereference later in this function would be caught by static analysis
     * or a runtime sanitizer. */
    return 0;
}

/* -------------------------------------------------------------
