#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>
#include <float.h>
#include <string.h>

#define INPUT_BUF_SIZE 64   /* Large enough for typical numeric input */

/* Helper: read a line from stdin safely */
static int read_line(char *buf, size_t buflen)
{
    if (fgets(buf, (int)buflen, stdin) == NULL) {
        return -1;                     /* I/O error or EOF */
    }
    /* Remove trailing newline, if present */
    buf[strcspn(buf, "\n")] = '\0';
    return 0;
}

/* Helper: parse an integer with range checking */
static int parse_int(const char *s, int *out)
{
    char *endptr = NULL;
    long val;

    errno = 0;
    val = strtol(s, &endptr, 10);

    /* Detect conversion errors */
    if (errno != 0 || endptr == s || *endptr != '\0')
        return -1;

    /* Ensure the value fits in an int */
    if (val < INT_MIN || val > INT_MAX)
        return -1;

    *out = (int)val;
    return 0;
}

/* Helper: parse a float with range checking */
static int parse_float(const char *s, float *out)
{
    char *endptr = NULL;
    double val;

    errno = 0;
    val = strtod(s, &endptr);

    if (errno != 0 || endptr == s || *endptr != '\0')
        return -1;

    /* Ensure the value fits in a float */
    if (val < -FLT_MAX || val > FLT_MAX)
        return -1;

    *out = (float)val;
    return 0;
}

/* Secure replacement for the original case block */
