#include <stddef.h>   // for size_t
#include <stdlib.h>   // for malloc, calloc, free
#include <limits.h>   // for SIZE_MAX
#include <string.h>   // for memset (optional)

#define MAX_ROWS 1024   /* example limits – adjust to your domain */
#define MAX_COLS  256

/* Error codes – extend as needed */
typedef enum {
    DB_SUCCESS          = 0,
    DB_ERR_NULL_PTR     = 1,   /* caller passed NULL for Database*   */
    DB_ERR_ALLOC_DB     = 2,   /* allocation of db->data failed      */
    DB_ERR_ALLOC_ROW    = 3    /* allocation of a row failed          */
} db_error_t;

/* Forward declaration of the row‑type */
typedef struct {
    char *name;
    int   age;
    char *city;
} Person;

/* Database container */
typedef struct {
    size_t   num_rows;
    size_t   num_cols;
    Person **data;          /* pointer to an array of row pointers */
} Database;

/* -----------------------------------------------------------------
 * Helper: safely release all memory owned by a Database instance.
 * It tolerates NULL pointers and partially‑initialised structures.
 * ----------------------------------------------------------------- */
static void free_database(Database *db)
{
    if (db == NULL) {
        return;
    }

    if (db->data != NULL) {
        for (size_t i = 0; i < db->num_rows; ++i) {
            free(db->data[i]);          /* each row (or NULL) */
        }
        free(db->data);
        db->data = NULL;
    }

    db->num_rows = 0;
    db->num_cols = 0;
}

/* -----------------------------------------------------------------
 * Secure initialisation
 * ----------------------------------------------------------------- */
int init_database(Database *db)
{
    /* 1️⃣ Validate caller argument */
    if (db == NULL) {
        return DB_ERR_NULL_PTR;
    }

    /* 2️⃣ Guard against overflow in the allocation size:
     *    (MAX_ROWS * sizeof(Person *)) must not exceed SIZE_MAX.
     */
    if (MAX_ROWS > SIZE_MAX / sizeof(Person *)) {
        return DB_ERR_ALLOC_DB;   /* unrealistic limit – fail fast */
    }

    /* 3️⃣ Allocate the top‑level array of row pointers.
     *    Use calloc to guarantee that all entries start as NULL,
     *    simplifying error‑cleanup.
     */
    db->data = (Person **)calloc(MAX_ROWS, sizeof(Person *));
    if (db->data == NULL) {
        return DB_ERR_ALLOC_DB;
    }

    db->num_rows = MAX_ROWS;
    db->num_cols = MAX_COLS;

    /* 4️⃣ Allocate each row and initialise its cells.
     *    We also protect against overflow for the inner allocation.
     */
    for (size_t i = 0; i < db->num_rows; ++i) {
        /* Overflow check for (MAX_COLS * sizeof(Person)) */
        if (MAX_COLS > SIZE_MAX / sizeof(Person)) {
            free_database(db);
            return DB_ERR_ALLOC_ROW;
        }

        db->data[i] = (Person *)calloc(MAX_COLS, sizeof(Person));
        if (db->data[i] == NULL) {
            /* Allocation failed – clean up everything allocated so far */
            free_database(db);
            return DB_ERR_ALLOC_ROW;
        }

        /* At this point each Person struct is zero‑filled:
         *   name == NULL, age == 0, city == NULL
         * No explicit per‑field assignment is required.
         */
    }

    /* Successful initialisation */
    return DB_SUCCESS;
}
