**Secure remediation for the `extract_domain` function**

Below is a hardened implementation that eliminates the NULL‑pointer dereference, adds robust bounds checking, and follows secure‑by‑design best practices (no buffer over‑reads, no integer under‑flow, and proper error handling). All allocated memory is validated and the caller is responsible for freeing the returned string.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>

#define MAX_DOMAIN_LENGTH 256   /* Adjust to the maximum domain size you expect */

/**
 * @brief Extracts the domain part (the substring after the last '.') from a URL.
 *
 * @param url  Null‑terminated input string. Must not be NULL.
 * @return Pointer to a newly allocated, null‑terminated domain string on success,
 *         or NULL on failure (errno is set accordingly).
 *
 * @note The caller must free() the returned pointer when it is no longer needed.
 */
char *extract_domain(const char *url)
{
    /* ---------- Input validation ---------- */
    if (url == NULL) {
        errno = EINVAL;               /* Invalid argument */
        return NULL;
    }

    size_t url_len = strlen(url);
    if (url_len == 0) {
        errno = EINVAL;
        return NULL;
    }

    /* ---------- Find the last '.' character ---------- */
    const char *last_dot = strrchr(url, '.');
    if (last_dot == NULL) {
        /* No dot found – cannot extract a domain */
        errno = ENOENT;
        return NULL;
    }

    /* Move past the dot to the start of the domain */
    const char *domain_start = last_dot + 1;
    size_t domain_len = url_len - (domain_start - url);

    /* ---------- Enforce maximum domain length ---------- */
    if (domain_len == 0) {
        errno = EINVAL;               /* Empty domain */
        return NULL;
    }
    if (domain_len >= MAX_DOMAIN_LENGTH) {
        errno = ENAMETOOLONG;         /* Domain too long for our buffer */
        return NULL;
    }

    /* ---------- Allocate and copy the domain safely ---------- */
    char *domain = malloc(domain_len + 1);   /* +1 for the terminating NUL */
    if (domain == NULL) {
        errno = ENOMEM;               /* Allocation failure */
        return NULL;
    }

    /* Use memcpy because we already know the exact length; then NUL‑terminate */
    memcpy(domain, domain_start, domain_len);
    domain[domain_len] = '\0';

    return domain;
}

/* -------------------------------------------------------------------------- */
/* Example usage (for illustration only – remove in production code)          */
#ifdef TEST_EXTRACT_DOMAIN
int main(void)
{
    const char *test_url = "https://sub.example.com";
    char *domain = extract_domain(test_url);
    if (domain) {
        printf("Domain: %s\n", domain);
        free(domain);
    } else {
        perror("extract_domain failed");
    }
    return 0;
}
#endif
