```c
#include <stddef.h>   // for size_t
#include <stdlib.h>   // for malloc, free
#include <string.h>   // for strlen, memcpy
#include <errno.h>    // for errno, ENOMEM, EINVAL

/**
 * Decrypts a XOR‑encrypted ciphertext with the supplied key.
 *
 * @param ciphertext  Null‑terminated string to decrypt. Must not be NULL.
 * @param key         Null‑terminated key string. Must not be NULL and must have length > 0.
 *
 * @return Pointer to a newly allocated null‑terminated plaintext on success,
 *         or NULL on any error (malloc failure, invalid arguments, etc.).
 *         The caller is responsible for freeing the returned buffer.
 */
char *decrypt(const char *ciphertext, const char *key)
{
    /* ---------- Input validation ---------- */
    if (ciphertext == NULL || key == NULL) {
        errno = EINVAL;               // invalid argument
        return NULL;
    }

    size_t ciphertext_len = strlen(ciphertext);
    size_t key_len        = strlen(key);

    if (key_len == 0) {               // avoid division‑by‑zero
        errno = EINVAL;
        return NULL;
    }

    /* ---------- Safe allocation ---------- */
    /* Check for overflow: ciphertext_len + 1 must fit in size_t */
    if (ciphertext_len == SIZE_MAX) {
        errno = EINVAL;
        return NULL;
    }

    char *plaintext = malloc(ciphertext_len + 1);
    if (plaintext == NULL) {
        errno = ENOMEM;               // out of memory
        return NULL;
    }

    /* ---------- Decryption loop (constant‑time optional) ---------- */
    for (size_t i = 0; i < ciphertext_len; ++i) {
        /* XOR each byte with the corresponding key byte (key repeats). */
        plaintext[i] = ciphertext[i] ^ key[i % key_len];
    }
    plaintext[ciphertext_len] = '\0';   // NUL‑terminate safely

    return plaintext;
}
