    size_t width;   /* number of columns  */
    size_t height;  /* number of rows     */
    cell_t **grid;  /* flat array of pointers: grid[width * height] */
} grid_t;

/* ----------------------------------------------------------------------
 * Helper: safe multiplication that detects overflow.
 * Returns 0 on overflow, otherwise the product in *out.
 * ---------------------------------------------------------------------- */
static int safe_mul_size_t(size_t a, size_t b, size_t *out)
{
    if (a == 0 || b == 0) {
        *out = 0;
        return 1;
    }
    if (a > SIZE_MAX / b) {
        return 0;               // overflow
    }
    *out = a * b;
    return 1;
}

/* ----------------------------------------------------------------------
 * Function: grid_create
 *   Allocates and initialises a grid of the requested dimensions.
 *   On any allocation failure the function cleans up and returns NULL.
 * ---------------------------------------------------------------------- */
grid_t *grid_create(size_t width, size_t height)
{
    /* ------------------------------------------------------------------
     * 1️⃣ Validate dimensions (optional but recommended)
     * ------------------------------------------------------------------ */
    if (width == 0 || height == 0) {
        fprintf(stderr, "grid dimensions must be non‑zero\n");
        return NULL;
    }

    /* ------------------------------------------------------------------
     * 2️⃣ Allocate the top‑level grid structure
     * ------------------------------------------------------------------ */
    grid_t *grid = malloc(sizeof(*grid));
    if (!grid) {
        perror("malloc(grid_t)");
        return NULL;
    }

    grid->width  = width;
    grid->height = height;

    /* ------------------------------------------------------------------
     * 3️⃣ Allocate the flat array of cell pointers (width * height)
     * ------------------------------------------------------------------ */
    size_t cell_ptr_count;
    if (!safe_mul_size_t(width, height, &cell_ptr_count)) {
        fprintf(stderr, "grid dimensions cause size overflow\n");
        free(grid);
        return NULL;
    }

    grid->grid = calloc(cell_ptr_count, sizeof(cell_t *));
    if (!grid->grid) {
        perror("calloc(grid->grid)");
        free(grid);
        return NULL;
    }

    /* ------------------------------------------------------------------
     * 4️⃣ Allocate each individual cell and initialise it.
     *    Index = i * height + j  (row‑major order)
     * ------------------------------------------------------------------ */
    for (size_t i = 0; i < width; ++i) {
        for (size_t j = 0; j < height; ++j) {
            size_t idx = i * height + j;   // safe, no overflow because idx < cell_ptr_count

            cell_t *c = malloc(sizeof(*c));
            if (!c) {
                perror("malloc(cell_t)");
                /* ---- Cleanup partially allocated grid ------------------- */
                for (size_t k = 0; k < idx; ++k) {
                    free(grid->grid[k]);
                }
                free(grid->grid);
                free(grid);
                return NULL;
            }

            /* Initialise the cell – no uninitialised data left */
            c->x     = (int)i;          // logical coordinate, not multiplied by CELL_SIZE
            c->y     = (int)j;
            c->alive = 1;

            grid->grid[idx] = c;
        }
    }

    return grid;
}

/* ----------------------------------------------------------------------
 * Function: grid_destroy
 *   Frees all memory allocated by grid_create.
 * ---------------------------------------------------------------------- */
void grid_destroy(grid_t *grid)
{
