    /* Detect overflow using the reciprocal of the maximum representable value.
     * The test is mathematically equivalent to: |a| > DBL_MAX / |b|
     */
    double limit = DBL_MAX / fabs(b);
    if (fabs(a) > limit)
        return false;               // would overflow

    *out_product = a * b;
    return true;
}

/* -------------------------------------------------------------------------
