 * ------------------------------------------------------------------------- */
static bool safe_add(double a, double b, double *out_sum)
{
    if (!isfinite(a) || !isfinite(b))
        return false;

    /* If b is positive, ensure a <= DBL_MAX - b.
     * If b is negative, ensure a >= -DBL_MAX - b (but we only add non‑negative
     * values in this context, so the positive‑branch suffices). */
    if (b > 0.0 && a > DBL_MAX - b)
        return false;               // would overflow

    *out_sum = a + b;
    return true;
}

