/* Helper: fill a buffer with cryptographically‑secure random bytes.
 * Returns 0 on success, -1 on failure (errno is set). */
static int secure_random_bytes(void *buf, size_t nbytes)
{
#if defined(__linux__) && defined(SYS_getrandom)
    ssize_t ret = getrandom(buf, nbytes, 0);
    if (ret == (ssize_t)nbytes) {
        return 0;
    }
    /* getrandom may return -1 with EINTR – retry once */
    if (ret == -1 && errno == EINTR) {
        ret = getrandom(buf, nbytes, 0);
        if (ret == (ssize_t)nbytes) {
            return 0;
        }
    }
    return -1;   /* errno already set */
#else
    /* Portable fallback: /dev/urandom */
    FILE *f = fopen("/dev/urandom", "rb");
    if (!f) return -1;
    size_t read = fread(buf, 1, nbytes, f);
    fclose(f);
    return (read == nbytes) ? 0 : -1;
#endif
}

/* Generate a random lower‑case word of length puzzle->len.
 * Returns 0 on success, -1 on error (e.g., invalid arguments,
 * allocation mismatch, or RNG failure). */
int generate_word(struct puzzle *puzzle)
{
    if (puzzle == NULL) {
        errno = EINVAL;
        return -1;
    }

    /* Validate length against the static buffer size */
    if (puzzle->len == 0 || puzzle->len > PUZZLE_MAX_WORD_LEN - 1) {
        errno = EINVAL;
        return -1;
    }

    /* Fill a temporary buffer with random bytes */
    unsigned char rand_bytes[PUZZLE_MAX_WORD_LEN];
    if (secure_random_bytes(rand_bytes, puzzle->len) != 0) {
        /* RNG failure – propagate errno */
        return -1;
    }

    /* Map each random byte to 'a'‑'z' */
    for (size_t i = 0; i < puzzle->len; ++i) {
        puzzle->word[i] = 'a' + (rand_bytes[i] % 26);
    }

    /* NUL‑terminate the string for safe downstream use */
    puzzle->word[puzzle->len] = '\0';
    return 0;
}
