   Helper: safely read an integer from stdin.
   Returns true on success, false on EOF or invalid input.
   The parsed value is stored in *out_val.
   ------------------------------------------------------------- */
static bool read_int_from_stdin(int *out_val)
{
    /* 64‑byte line buffer is more than enough for any decimal int
       plus optional whitespace and a trailing newline. */
    char line[64];

    /* fgets reads at most sizeof(line)-1 characters and always NUL‑terminates. */
    if (fgets(line, sizeof(line), stdin) == NULL) {
        /* EOF or read error */
        return false;
    }

    /* Remove trailing newline, if present (optional, not required for strtol). */
    char *nl = line;
    while (*nl != '\0') {
        if (*nl == '\n') {
            *nl = '\0';
            break;
        }
        ++nl;
    }

    /* Convert with strict error checking. */
    char *endptr = NULL;
    errno = 0;
    long val = strtol(line, &endptr, 10);

    /* 1. No digits were found */
    if (endptr == line) {
        fprintf(stderr, "Error: input is not a valid integer.\n");
        return false;
    }
    /* 2. Trailing non‑whitespace characters (e.g., "123abc") */
    while (*endptr != '\0') {
        if (!isspace((unsigned char)*endptr)) {
            fprintf(stderr, "Error: unexpected characters after integer.\n");
            return false;
        }
        ++endptr;
    }
    /* 3. Range errors */
    if ((errno == ERANGE && (val == LONG_MAX || val == LONG_MIN)) ||
        val > INT_MAX || val < INT_MIN) {
        fprintf(stderr, "Error: integer out of range.\n");
        return false;
    }

    *out_val = (int)val;
    return true;
}

