/* -----------------------------------------------------------------
 *  initialize_array – safely fill an integer array with pseudo‑random
 *  values in the range [0, size‑1].
 *
 *  Parameters
 *      array : pointer to the first element of the array (must be non‑NULL)
 *      size  : number of elements to initialise (must be >0 and ≤ ARRAY_SIZE)
 *
 *  Returns
 *      0 on success, -1 on error (errno set accordingly)
 * -----------------------------------------------------------------*/
int initialize_array(int *array, size_t size)
{
    /* 1️⃣ Validate arguments */
    if (array == NULL) {
        errno = EINVAL;               /* invalid pointer */
        return -1;
    }
    if (size == 0 || size > ARRAY_SIZE) {
        errno = EINVAL;               /* invalid size */
        return -1;
    }

    /* 2️⃣ Seed the PRNG once – use a thread‑local generator for better safety */
    static _Thread_local unsigned int seed = 0;
    if (seed == 0) {
        struct timespec ts;
        if (clock_gettime(CLOCK_REALTIME, &ts) != 0) {
            /* fallback if clock_gettime fails */
            seed = (unsigned int)time(NULL);
        } else {
            seed = (unsigned int)(ts.tv_sec ^ ts.tv_nsec);
        }
    }

    /* 3️⃣ Fill the array – use rand_r (re‑entrant) to avoid global state */
    for (size_t i = 0; i < size; ++i) {
        /* The modulo operation is safe because size ≤ ARRAY_SIZE ≤ UINT_MAX */
        array[i] = (int)(rand_r(&seed) % size);
    }

    return 0;
}

/* -----------------------------------------------------------------
 *  time_diff – compute the elapsed time between two `timespec` values.
 *
 *  Returns the difference as a double representing **seconds** (fractional).
 * -----------------------------------------------------------------*/
static inline double time_diff(struct timespec start, struct timespec end)
{
    /* Normalise nanoseconds to seconds and handle possible wrap‑around */
    long sec  = end.tv_sec  - start.tv_sec;
    long nsec = end.tv_nsec - start.tv_nsec;

    if (nsec < 0) {
        --sec;
        nsec += 1000000000L;
    }

    return (double)sec + (double)nsec / 1e9;
}

