/* ----------------------------------------------------------------------
 * Data structure
 * ---------------------------------------------------------------------- */
typedef struct {
    char *text;   /* dynamically allocated buffer */
    size_t size;  /* current allocated size (in bytes) */
    size_t used;  /* number of bytes currently stored (excluding NUL) */
} TextBlock;

/* ----------------------------------------------------------------------
 * Helper: safe multiplication with overflow detection
 * ---------------------------------------------------------------------- */
static int safe_add_size(size_t a, size_t b, size_t *out)
{
    if (a > SIZE_MAX - b) {
        return 0;               // overflow
    }
    *out = a + b;
    return 1;
}

/* ----------------------------------------------------------------------
 * Initialise a TextBlock
 *
 * Guarantees:
 *   – `block` must be a valid, non‑NULL pointer supplied by the caller.
 *   – On success, `block->text` points to a zero‑filled buffer of `size`
 *     bytes, `block->size` equals `size`, and `block->used` is 0.
 *   – On any failure the function returns -1 and leaves the structure
 *     unchanged (except that `block->text` is set to NULL if allocation
 *     fails).
 * ---------------------------------------------------------------------- */
int textBlock_init(TextBlock *block, size_t size)
{
