        return -1;
    }

    /* Guard against absurdly large allocations that could cause OOM */
    if (size == 0 || size > SIZE_MAX / 2) {
        return -1;
    }

    char *buf = calloc(1, size);          // zero‑initialised, safe malloc
    if (buf == NULL) {
        block->text = NULL;
        block->size = 0;
        block->used = 0;
        return -1;
    }

    block->text = buf;
    block->size = size;
    block->used = 0;
    return 0;
}

/* ----------------------------------------------------------------------
 * Append text to a TextBlock
 *
 * Guarantees:
 *   – Handles NULL pointers safely.
 *   – Detects integer overflow when computing the new buffer size.
 *   – Checks the result of `realloc`; on failure the original buffer
 *     remains intact.
 *   – Guarantees NUL‑termination of the stored string.
 * ---------------------------------------------------------------------- */
int textBlock_append(TextBlock *block, const char *text, size_t length)
{
    if (block == NULL || text == NULL) {
        return -1;
    }

    /* Compute required size: existing used + new length + 1 for NUL */
    size_t required;
    if (!safe_add_size(block->used, length, &required) ||
        !safe_add_size(required, 1, &required)) {
        /* overflow */
        return -1;
    }

    /* Grow the buffer only if needed */
    if (required > block->size) {
        size_t newSize = block->size ? block->size : 1;
        while (newSize < required) {
            if (!safe_add_size(newSize, newSize, &newSize)) { // double, check overflow
                return -1;
            }
        }

        char *tmp = realloc(block->text, newSize);
        if (tmp == NULL) {
            /* Allocation failed – keep original buffer untouched */
            return -1;
        }

        /* Zero‑initialize the newly allocated region to avoid leaking data */
        if (newSize > block->size) {
            memset(tmp + block->size, 0, newSize - block->size);
        }

        block->text = tmp;
        block->size = newSize;
    }

    /* Safe copy – we already know there is enough space */
    memcpy(block->text + block->used, text, length);
    block->used += length;
    block->text[block->used] = '\0';   // NUL‑terminate

    return 0;
}

/* ----------------------------------------------------------------------
 * Clean‑up helper
 * ---------------------------------------------------------------------- */
void textBlock_free(TextBlock *block)
{
    if (block == NULL) {
        return;
    }
    free(block->text);
    block->text = NULL;
    block->size = 0;
    block->used = 0;
}
