 *  Secure grid initialisation and thread launch
 *  -------------------------------------------------------------
 *  Assumptions (documented for future maintainers):
 *   • grid->width  and grid->height are positive and fit in size_t.
 *   • CELL_SIZE is a compile‑time constant (e.g. 1) that does not
 *     cause overflow when multiplied by the dimensions.
 *   • thread_func has the prototype:
 *         void *thread_func(void *arg);
 *   • The grid structure is defined as:
 *
 *     typedef struct {
 *         size_t width;
 *         size_t height;
 *         cell_t **grid;   // array of pointers to cell_t
 *         pthread_mutex_t lock; // protects mutable fields if needed
 *     } grid_t;
 *
 * ------------------------------------------------------------- */

#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <errno.h>

#define CELL_SIZE 1          /* adjust as required; must be >0 */
#define THREAD_COUNT 10

/* -----------------------------------------------------------------
 * Helper: safe multiplication that detects overflow.
 * Returns 0 on overflow, otherwise the product.
 * ----------------------------------------------------------------- */
static size_t safe_mul(size_t a, size_t b)
{
    if (a == 0 || b == 0) return 0;
    if (SIZE_MAX / a < b) return 0;   /* overflow */
    return a * b;
}

/* -----------------------------------------------------------------
 * Initialise the grid – returns 0 on success, non‑zero on failure.
 * ----------------------------------------------------------------- */
static int init_grid(grid_t *grid)
{
    if (!grid) return EINVAL;

    /* -------------------------------------------------------------
     * 1. Validate dimensions – they must be non‑zero and safe to multiply.
     * ------------------------------------------------------------- */
    if (grid->width == 0 || grid->height == 0) {
        fprintf(stderr, "Invalid grid dimensions.\n");
        return EINVAL;
    }

    size_t total_cells = safe_mul(grid->width, grid->height);
    if (total_cells == 0) {
        fprintf(stderr, "Grid size overflow.\n");
        return EOVERFLOW;
    }

    /* -------------------------------------------------------------
     * 2. Allocate the array that will hold pointers to each cell.
     * ------------------------------------------------------------- */
    grid->grid = calloc(total_cells, sizeof(cell_t *));
    if (!grid->grid) {
        perror("calloc(grid->grid)");
        return ENOMEM;
    }

    /* -------------------------------------------------------------
     * 3. Allocate each cell and initialise its fields.
     * ------------------------------------------------------------- */
    for (size_t i = 0; i < grid->width; ++i) {
        for (size_t j = 0; j < grid->height; ++j) {
            size_t idx = i * grid->height + j;   /* row‑major order */

            cell_t *c = malloc(sizeof(cell_t));
            if (!c) {
                perror("malloc(cell_t)");
                /* Clean‑up already allocated cells before aborting */
                for (size_t k = 0; k < idx; ++k) {
                    free(grid->grid[k]);
                }
                free(grid->grid);
                grid->grid = NULL;
                return ENOMEM;
            }

            c->x = (int)(i * CELL_SIZE);
            c->y = (int)(j * CELL_SIZE);
            c->alive = 1;

            grid->grid[idx] = c;
        }
    }

    /* -------------------------------------------------------------
     * 4. Initialise a mutex if the grid will be accessed concurrently.
     *    (If thread_func never mutates shared fields, this can be omitted.)
     * ------------------------------------------------------------- */
    if (pthread_mutex_init(&grid->lock, NULL) != 0) {
        perror("pthread_mutex_init");
        /* Clean‑up allocated cells */
        for (size_t k = 0; k < total_cells; ++k) {
            free(grid->grid[k]);
        }
        free(grid->grid);
        grid->grid = NULL;
        return errno;
    }

    return 0;   /* success */
}

/* -----------------------------------------------------------------
 * Clean‑up routine – frees every cell and the container array.
 * ----------------------------------------------------------------- */
static void destroy_grid(grid_t *grid)
{
    if (!grid || !grid->grid) return;

    size_t total_cells = grid->width * grid->height;
    for (size_t i = 0; i < total_cells; ++i) {
        free(grid->grid[i]);
    }
    free(grid->grid);
    grid->grid = NULL;

    pthread_mutex_destroy(&grid->lock);
}

/* -----------------------------------------------------------------
 * Main entry point (example usage)
 * ----------------------------------------------------------------- */
int main(void)
{
    grid_t my_grid = {
        .width  = 100,   /* example dimensions */
        .height = 80,
        .grid   = NULL
    };

    if (init_grid(&my_grid) != 0) {
        fprintf(stderr, "Failed to initialise grid – aborting.\n");
        return EXIT_FAILURE;
    }

    /* -------------------------------------------------------------
     * 5. Create worker threads, checking each creation result.
     * ------------------------------------------------------------- */
    pthread_t threads[THREAD_COUNT];
    for (int t = 0; t < THREAD_COUNT; ++t) {
        int rc = pthread_create(&threads[t], NULL, thread_func, &my_grid);
        if (rc != 0) {
            fprintf(stderr, "pthread_create failed for thread %d: %s\n",
                    t, strerror(rc));
            /* Cancel any already‑started threads and clean‑up */
            for (int j = 0; j < t; ++j) {
                pthread_cancel(threads[j]);
            }
            destroy_grid(&my_grid);
            return EXIT_FAILURE;
        }
    }

    /* -------------------------------------------------------------
     * 6. Wait for all threads to finish.
     * ------------------------------------------------------------- */
    for (int t = 0; t < THREAD_COUNT; ++t) {
        int rc = pthread_join(threads[t], NULL);
        if (rc != 0) {
            fprintf(stderr, "pthread_join failed for thread %d: %s\n",
                    t, strerror(rc));
        }
    }

    /* -------------------------------------------------------------
     * 7. Clean‑up the grid before exiting.
     * ------------------------------------------------------------- */
    destroy_grid(&my_grid);
    return EXIT_SUCCESS;
}
