   Returns 0 on success and stores the value in *out.
   Returns non‑zero on error (invalid input, overflow, etc.). */
static int read_double(const char *prompt, double *out)
{
    char buf[INPUT_BUF_SIZE];

    /* Prompt the user */
    if (printf("%s", prompt) < 0) {
        return -1;               /* I/O error */
    }
    fflush(stdout);             /* Ensure prompt is displayed */

    /* Read a line – fgets guarantees we never write past the buffer */
    if (fgets(buf, sizeof(buf), stdin) == NULL) {
        return -1;               /* EOF or error */
    }

    /* Strip trailing newline, if present */
    buf[strcspn(buf, "\n")] = '\0';

    /* Convert the string to double, with strict error checking */
    char *endptr = NULL;
    errno = 0;
    double val = strtod(buf, &endptr);

    /* Detect conversion errors */
    if (errno == ERANGE && (val == HUGE_VAL || val == -HUGE_VAL)) {
        fprintf(stderr, "Error: numeric value out of range.\n");
        return -1;
    }
    if (errno != 0 && val == 0.0) {
        perror("strtod");
        return -1;
    }
    if (endptr == buf) {
        fprintf(stderr, "Error: no digits were found.\n");
        return -1;
    }
    /* Ensure the whole line was consumed (no trailing garbage) */
    while (*endptr != '\0') {
        if (!isspace((unsigned char)*endptr)) {
            fprintf(stderr, "Error: unexpected character '%c' in input.\n", *endptr);
            return -1;
        }
        ++endptr;
    }

    *out = val;
    return 0;
}

