#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <limits.h>

/* ----------------------------------------------------------------------
 * Helper: safe addition for size_t (detects overflow)
 * Returns 0 on success, non‑zero on overflow.
 * ---------------------------------------------------------------------- */
static int size_add_overflow(size_t a, size_t b, size_t *out)
{
    if (a > SIZE_MAX - b) {
        return -1;               /* overflow would occur */
    }
    *out = a + b;
    return 0;
}

/* ----------------------------------------------------------------------
 * Secure function that reads a file, allocates buffers, and builds the
 * XOR key.  All error paths clean up allocated resources before returning.
 * ---------------------------------------------------------------------- */
int process_file(const char *filename,
                 const unsigned char *key,
                 size_t key_len,
                 unsigned char **out_plaintext,
                 unsigned char **out_xor_key,
                 size_t *out_file_size)
{
    FILE *file_in = NULL;
    unsigned char *plaintext = NULL;
    unsigned char *xor_key = NULL;
    size_t file_size = 0;
    size_t xor_key_len = 0;
    int rc = -1;                     /* default to failure */

    /* --------------------------------------------------------------
     * Basic argument validation
     * -------------------------------------------------------------- */
    if (!filename || !key || key_len == 0 ||
        !out_plaintext || !out_xor_key || !out_file_size) {
        errno = EINVAL;
        goto cleanup;
    }

    /* --------------------------------------------------------------
     * Open the file safely
     * -------------------------------------------------------------- */
    file_in = fopen(filename, "rb");
    if (!file_in) {
        /* errno already set by fopen */
        goto cleanup;
    }

    /* --------------------------------------------------------------
     * Determine file size (portable, avoids fseek/ftell pitfalls)
     * -------------------------------------------------------------- */
    if (fseek(file_in, 0, SEEK_END) != 0) {
        goto cleanup;
    }
    long ftell_ret = ftell(file_in);
    if (ftell_ret < 0) {
        goto cleanup;
    }
    file_size = (size_t)ftell_ret;
    if (fseek(file_in, 0, SEEK_SET) != 0) {
        goto cleanup;
    }

    /* --------------------------------------------------------------
     * Guard against absurdly large files that could exhaust memory.
     * Adjust the limit according to your threat model / environment.
     * -------------------------------------------------------------- */
    const size_t MAX_ALLOWED_FILE = 100 * 1024 * 1024;   /* 100 MiB */
    if (file_size > MAX_ALLOWED_FILE) {
        errno = EFBIG;
        goto cleanup;
    }

    /* --------------------------------------------------------------
     * Allocate plaintext buffer (exact size)
     * -------------------------------------------------------------- */
    plaintext = malloc(file_size);
    if (!plaintext) {
        goto cleanup;
    }

    /* --------------------------------------------------------------
     * Read the file contents
     * -------------------------------------------------------------- */
    size_t bytes_read = fread(plaintext, 1, file_size, file_in);
    if (bytes_read != file_size) {
        /* Partial read – treat as error */
        errno = EIO;
        goto cleanup;
    }

    /* --------------------------------------------------------------
     * Compute safe size for xor_key = file_size + 1 (null‑terminator)
     * -------------------------------------------------------------- */
    if (size_add_overflow(file_size, 1, &xor_key_len) != 0) {
        errno = EOVERFLOW;
        goto cleanup;
    }

    xor_key = malloc(xor_key_len);
    if (!xor_key) {
        goto cleanup;
    }

    /* --------------------------------------------------------------
     * Build the XOR key, ensuring we never read past `key_len`
     * -------------------------------------------------------------- */
    for (size_t i = 0; i < file_size; ++i) {
        xor_key[i] = key[i % key_len];
    }
    xor_key[file_size] = '\0';   /* explicit terminator for string use */

    /* --------------------------------------------------------------
     * Success – hand ownership of buffers to the caller
     * -------------------------------------------------------------- */
    *out_plaintext = plaintext;
    *out_xor_key   = xor_key;
    *out_file_size = file_size;

    plaintext = NULL;   /* prevent double‑free in cleanup */
    xor_key   = NULL;
    rc = 0;              /* success */

cleanup:
    if (file_in) {
        fclose(file_in);
    }
    if (plaintext) {
        /* Zero‑out before free if the data is sensitive */
        memset(plaintext, 0, file_size);
        free(plaintext);
    }
    if (xor_key) {
        memset(xor_key, 0, xor_key_len);
        free(xor_key);
    }
    return rc;
}
