 * ---------------------------------------------------------------------- */
static ParseResult extract_year(const char *date_string, int *year_out)
{
    char *token = NULL;
    char *saveptr = NULL;
    char *tmp = NULL;
    ParseResult rc = PARSE_ERR_BAD_FORMAT;

    if (date_string == NULL || year_out == NULL) {
        return PARSE_ERR_NULL_INPUT;
