    tmp = strdup(date_string);
    if (tmp == NULL) {
        return PARSE_ERR_OVERFLOW;   /* out‑of‑memory is treated as overflow */
    }

    /* Skip day */
    token = strtok_r(tmp, "/", &saveptr);
    if (token == NULL) goto cleanup;

    /* Skip month */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) goto cleanup;

    /* Extract year */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) goto cleanup;

    rc = safe_str_to_int(token, year_out);

cleanup:
    free(tmp);
    return rc;
}

/* ----------------------------------------------------------------------
 * Parse a full date string into a Date structure.
 * Returns PARSE_OK on success; otherwise an error code.
 * ---------------------------------------------------------------------- */
ParseResult parse_date(const char *date_string, Date **date_out)
{
    char *token = NULL;
    char *saveptr = NULL;
    char *tmp = NULL;
    int day = 0, month = 0, year = 0;
    ParseResult rc = PARSE_ERR_BAD_FORMAT;

    if (date_string == NULL || date_out == NULL) {
        return PARSE_ERR_NULL_INPUT;
    }

    /* Allocate the result object early so we can clean up on error */
    *date_out = (Date *)malloc(sizeof(Date));
    if (*date_out == NULL) {
        return PARSE_ERR_OVERFLOW;
    }

    /* Duplicate the input because strtok_r mutates it */
    tmp = strdup(date_string);
    if (tmp == NULL) {
        rc = PARSE_ERR_OVERFLOW;
        goto error;
    }

    /* Day */
