    if (token == NULL) { rc = PARSE_ERR_BAD_FORMAT; goto error; }
    rc = safe_str_to_int(token, &day);
    if (rc != PARSE_OK) goto error;

    /* Month */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) { rc = PARSE_ERR_BAD_FORMAT; goto error; }
    rc = safe_str_to_int(token, &month);
    if (rc != PARSE_OK) goto error;

    /* Year – reuse the helper for consistency */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) { rc = PARSE_ERR_BAD_FORMAT; goto error; }
    rc = safe_str_to_int(token, &year);
    if (rc != PARSE_OK) goto error;

    /* Basic range checks (adjust as needed for your domain) */
    if (day < 1 || day > 31 || month < 1 || month > 12) {
