    (*date_out)->month = month;
    (*date_out)->year  = year;

    rc = PARSE_OK;   /* success */

error:
    free(tmp);
    if (rc != PARSE_OK) {
        free(*date_out);
        *date_out = NULL;
    }
    return rc;
}

