    /* -----------------------------------------------------------------
       3️⃣  Safe subtraction: deltaRow = endRow - startRow
       ----------------------------------------------------------------- */
    int deltaRow;
    if (safe_sub_int(endRow, startRow, &deltaRow)) {
        return false;   // overflow – treat as invalid move
    }

    /* -----------------------------------------------------------------
       4️⃣  Simple one‑step diagonal move
       ----------------------------------------------------------------- */
    if (deltaRow == direction) {
        return (abs(endCol - startCol) == 1);
