```c
/*===  Secure Grid Allocation  ===========================================*/
/*  Author: Squad C – Remediation Assistant                               */
/*  Guarantees:                                                          */
/*   • No NULL‑pointer dereference                                         */
/*   • No out‑of‑bounds indexing                                           */
/*   • Checked arithmetic to avoid size_t overflow                         */
/*   • Full cleanup on any allocation failure                              */
/*=======================================================================*/

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <stddef.h>
#include <stdint.h>

/*--- Application‑specific constants ------------------------------------*/
#define WIDTH       64U          /* grid width  (must be >0) */
#define HEIGHT      48U          /* grid height (must be >0) */
#define CELL_SIZE   10U          /* logical size of a cell in pixels */

/*--- Data structures ---------------------------------------------------*/
typedef struct {
    int x;      /* logical X coordinate (pixel units) */
    int y;      /* logical Y coordinate (pixel units) */
    /* add other cell fields here */
} cell_t;

typedef struct {
    unsigned int width;   /* number of columns  */
    unsigned int height;  /* number of rows     */
    cell_t **grid;        /* pointer to an array of width*height cell pointers */
} grid_t;

/*--- Helper: safe multiplication (detects overflow) --------------------*/
static bool safe_mul_size_t(size_t a, size_t b, size_t *out)
{
    /* GCC/Clang built‑in; fallback to manual check for other compilers */
#if defined(__has_builtin)
#  if __has_builtin(__builtin_mul_overflow)
    return __builtin_mul_overflow(a, b, out);
#  endif
#endif
    /* Portable fallback */
    if (a == 0 || b == 0) {
        *out = 0;
        return false;
    }
    if (SIZE_MAX / a < b) {
        return true;               /* overflow */
    }
    *out = a * b;
    return false;
}

/*--- Allocate a fully‑initialised grid ----------------------------------*/
static grid_t *grid_create(unsigned int width,
                           unsigned int height,
                           unsigned int cell_size)
{
    /* Validate input dimensions early */
    if (width == 0 || height == 0) {
        fprintf(stderr, "Error: grid dimensions must be non‑zero.\n");
        return NULL;
    }

    /* Allocate the top‑level structure */
    grid_t *g = malloc(sizeof(*g));
    if (!g) {
        perror("malloc(grid_t)");
        return NULL;
    }
    g->width  = width;
    g->height = height;

    /* Allocate the pointer array: width * height entries */
    size_t ptr_cnt;
    if (safe_mul_size_t((size_t)width, (size_t)height, &ptr_cnt)) {
        fprintf(stderr, "Error: grid size overflow.\n");
        free(g);
        return NULL;
    }

    g->grid = malloc(ptr_cnt * sizeof(cell_t *));
    if (!g->grid) {
        perror("malloc(grid->grid)");
        free(g);
        return NULL;
    }

    /* Initialise each cell */
    for (unsigned int i = 0; i < width; ++i) {
        for (unsigned int j = 0; j < height; ++j) {
            size_t idx = (size_t)i * height + j;   /* linear index */

            cell_t *c = malloc(sizeof(*c));
            if (!c) {
                perror("malloc(cell_t)");
                /* Clean‑up everything allocated so far */
                for (unsigned int ii = 0; ii < i; ++ii) {
                    for (unsigned int jj = 0; jj < height; ++jj) {
                        free(g->grid[(size_t)ii * height + jj]);
                    }
                }
                for (unsigned int jj = 0; jj < j; ++jj) {
                    free(g->grid[(size_t)i * height + jj]);
                }
                free(g->grid);
                free(g);
                return NULL;
            }

            c->x = (int)(i * cell_size);
            c->y = (int)(j * cell_size);
            g->grid[idx] = c;
        }
    }

    return g;
}

/*--- De‑allocate a grid -------------------------------------------------*/
static void grid_destroy(grid_t *g)
{
    if (!g) return;

    size_t total = (size_t)g->width * g->height;
    for (size_t i = 0; i < total; ++i) {
        free(g->grid[i]);   /* each cell */
    }
    free(g->grid);          /* pointer array */
    free(g);                /* grid_t itself */
}

/*===  Example usage (main)  =============================================*/
int main(void)
{
    grid_t *grid = grid_create(WIDTH, HEIGHT, CELL_SIZE);
    if (!grid) {
        /* Allocation failed – already reported to stderr */
        return EXIT_FAILURE;
    }

    /* ------------------------------------------------------------------ */
    /* Insert your application logic here (e.g., render the grid, etc.)   */
    /* ------------------------------------------------------------------ */

    /* Clean up before exiting */
    grid_destroy(grid);
    return EXIT_SUCCESS;
}
```

