static unsigned char graph[MAX_N][MAX_N];   /* Fixed‑size, zero‑initialized */

static int parse_int(const char *str, int *out)
{
    char *endptr = NULL;
    long val = strtol(str, &endptr, 10);

    /* Detect conversion errors, overflow, or trailing characters */
    if (endptr == str || *endptr != '\0' ||
        ((val == LONG_MAX || val == LONG_MIN) && errno == ERANGE) ||
        val > INT_MAX || val < INT_MIN) {
        return -1;
    }

    *out = (int)val;
    return 0;
}

/* --------------------------------------------------------------------- */
