/*=====================================================================
 * sanitize_url
 *
 *  Copies a URL string into a destination buffer while allowing only
 *  alphanumeric characters, '-', '.', and '_' .  All other characters
 *  are replaced with '_' and a warning is emitted.
 *
 *  Parameters
 *      dest      – pointer to the destination buffer (must be non‑NULL)
 *      dest_len  – size of the destination buffer in bytes (must be >0)
 *      src       – pointer to the source URL string (must be non‑NULL)
 *
 *  Returns
 *      0  – success (dest contains a NUL‑terminated sanitized string)
 *     -1  – invalid arguments (NULL pointer or dest_len == 0)
 *     -2  – destination buffer too small to hold even an empty string
 *
 *  The function never writes past the end of the destination buffer and
 *  never dereferences a NULL pointer.
 *====================================================================*/
#include <stdio.h>
#include <ctype.h>
#include <stddef.h>   /* for size_t */

/* Return codes */
#define SANITIZE_OK            0
#define SANITIZE_EINVAL       -1
#define SANITIZE_ENOSPC       -2

int sanitize_url(char *dest, size_t dest_len, const char *src)
{
    /*--------------------------- 1. Validate arguments ---------------------------*/
    if (dest == NULL || src == NULL) {
        return SANITIZE_EINVAL;          /* NULL pointer supplied */
    }
    if (dest_len == 0) {
        return SANITIZE_EINVAL;          /* No space to write even a NUL byte */
    }

    /* Reserve space for the terminating NUL */
    size_t max_copy = dest_len - 1;      /* number of characters we may store */

    size_t i = 0;                        /* index into src */
    size_t out = 0;                      /* index into dest */

    /*--------------------------- 2. Copy & sanitise ---------------------------*/
    while (src[i] != '\0' && out < max_copy) {
        unsigned char ch = (unsigned char)src[i];   /* safe for isalnum() */

        if (isalnum(ch) || ch == '-' || ch == '.' || ch == '_') {
            dest[out] = (char)ch;
        } else {
            dest[out] = '_';
            /* Emit a diagnostic – use stderr to avoid mixing with normal output */
            fprintf(stderr,
                    "Warning: Invalid character (0x%02X) found in URL at position %zu. "
                    "Replaced with '_' .\n",
                    ch, i);
        }
        ++i;
        ++out;
    }

    /*--------------------------- 3. NUL‑terminate ---------------------------*/
    dest[out] = '\0';

    /* If we stopped because the source string is longer than the buffer,
       the caller can decide whether truncation is acceptable. */
    if (src[i] != '\0') {
        /* Destination buffer exhausted – signal truncation */
        return SANITIZE_ENOSPC;
    }

    return SANITIZE_OK;
}
