/*=====================================================================
  Secure string wrapper
  --------------------------------------------------------------------
  - Handles allocation failures gracefully.
  - Validates input arguments.
  - Uses size_t for lengths (the proper unsigned type for sizes).
  - Guarantees that free_string can be called safely multiple times.
=====================================================================*/

#include <stddef.h>   // size_t
#include <stdlib.h>   // malloc, free
#include <string.h>   // strlen, memcpy
#include <errno.h>    // errno, ENOMEM, EINVAL

/* ------------------------------------------------------------------ */
/*  Definition of the opaque string object                              */
/* ------------------------------------------------------------------ */
typedef struct {
    char   *data;   /* heap‑allocated, NUL‑terminated string */
    size_t  length; /* length *excluding* the terminating NUL */
} String;

/* ------------------------------------------------------------------ */
/*  Helper: safe duplication of a C‑string                               */
/* ------------------------------------------------------------------ */
static char *safe_strdup(const char *src, int *err)
{
    if (src == NULL) {
        if (err) *err = EINVAL;          /* caller passed a NULL pointer   */
        return NULL;
    }

    size_t len = strlen(src);
    /* +1 for the terminating NUL – overflow is impossible because
       strlen returns size_t and we add a constant 1. */
    char *dup = malloc(len + 1);
    if (!dup) {
        if (err) *err = ENOMEM;          /* allocation failure            */
        return NULL;
    }

    memcpy(dup, src, len + 1);           /* copies NUL byte as well       */
    if (err) *err = 0;
    return dup;
}

/* ------------------------------------------------------------------ */
/*  Constructor – creates a new String object                           */
/* ------------------------------------------------------------------ */
String *new_string(const char *str)
{
    /* Validate the caller’s argument early. */
    if (str == NULL) {
        errno = EINVAL;
        return NULL;
    }

    /* Allocate the wrapper structure. */
    String *s = malloc(sizeof(*s));
    if (!s) {
        errno = ENOMEM;
        return NULL;
    }

    /* Duplicate the payload safely. */
    int dup_err = 0;
    s->data = safe_strdup(str, &dup_err);
    if (!s->data) {
        /* Propagate the specific error to the caller. */
        free(s);
        errno = dup_err;   /* ENOMEM or EINVAL */
        return NULL;
    }

    s->length = strlen(s->data);   /* safe – s->data is non‑NULL */
    return s;
}

/* ------------------------------------------------------------------ */
/*  Destructor – releases all resources safely                           */
/* ------------------------------------------------------------------ */
void free_string(String *s)
{
    if (s == NULL) {
        return;                     /* idempotent – nothing to do */
    }

    /* Free the internal buffer first; free(NULL) is a no‑op. */
    free(s->data);
    s->data = NULL;                 /* avoid dangling pointer */

    /* Finally free the wrapper itself. */
    free(s);
}

/* ------------------------------------------------------------------ */
/*  Optional utility: retrieve a read‑only view of the string data      */
/* ------------------------------------------------------------------ */
const char *string_c_str(const String *s)
{
    return (s && s->data) ? s->data : NULL;
}

/* ------------------------------------------------------------------ */
/*  Optional utility: retrieve the stored length                         */
/* ------------------------------------------------------------------ */
size_t string_length(const String *s)
{
    return (s) ? s->length : 0;
}
