    struct node   *next;     /* Next neighbor in the list */
} Node;

/* Graph container */
typedef struct Graph {
    int   vertices;   /* Number of vertices in the graph */
    Node **adjList;   /* Array of adjacency‑list heads (size = vertices) */
} Graph;

/*---------------------------------------------------------------*/
/* Helper: allocate a new adjacency‑list node */
static Node *createNode(int vertex)
{
    Node *newNode = (Node *)malloc(sizeof(Node));
    if (newNode == NULL) {
        fprintf(stderr, "Error: malloc failed while creating node.\n");
        return NULL;
    }
    newNode->vertex = vertex;
    newNode->next   = NULL;
    return newNode;
}

/*---------------------------------------------------------------*/
/* Initialise a graph with the requested number of vertices.
 * Returns NULL on any allocation failure. */
static Graph *createGraph(int vertexCount)
{
    if (vertexCount <= 0) {
        fprintf(stderr, "Error: vertex count must be positive.\n");
        return NULL;
    }

    Graph *graph = (Graph *)malloc(sizeof(Graph));
    if (graph == NULL) {
        fprintf(stderr, "Error: malloc failed for Graph struct.\n");
        return NULL;
    }

    graph->vertices = vertexCount;

    /* Allocate and zero‑initialise the adjacency‑list array */
    graph->adjList = (Node **)calloc((size_t)vertexCount, sizeof(Node *));
    if (graph->adjList == NULL) {
        fprintf(stderr, "Error: calloc failed for adjacency list.\n");
        free(graph);
        return NULL;
    }

    return graph;
}

/*---------------------------------------------------------------*/
/* Add an undirected edge (u ↔ v).  Returns true on success. */
static bool addEdge(Graph *graph, int u, int v)
{
    if (graph == NULL ||
        u < 0 || u >= graph->vertices ||
        v < 0 || v >= graph->vertices) {
        fprintf(stderr, "Error: invalid parameters to addEdge.\n");
        return false;
    }

    /* Insert node v into u's list */
    Node *nodeU = createNode(v);
    if (nodeU == NULL) return false;
    nodeU->next = graph->adjList[u];
    graph->adjList[u] = nodeU;

    /* Insert node u into v's list (undirected graph) */
    Node *nodeV = createNode(u);
    if (nodeV == NULL) {
        /* Roll back the first insertion to keep graph consistent */
        graph->adjList[u] = nodeU->next;
        free(nodeU);
        return false;
    }
    nodeV->next = graph->adjList[v];
    graph->adjList[v] = nodeV;

    return true;
}

/*---------------------------------------------------------------*/
/* Release all memory owned by the graph */
static void freeGraph(Graph *graph)
{
    if (graph == NULL) return;

    for (int i = 0; i < graph->vertices; ++i) {
        Node *curr = graph->adjList[i];
        while (curr != NULL) {
            Node *tmp = curr;
            curr = curr->next;
            free(tmp);
        }
    }

    free(graph->adjList);
    free(graph);
}

/*---------------------------------------------------------------*/
/* Example driver – demonstrates safe usage */
int main(void)
{
    const int V = 5;                     /* total vertices in graph */
    Graph *graph = createGraph(V);
    if (graph == NULL) {
        /* Allocation failed – nothing else to do */
        return EXIT_FAILURE;
    }

    /* Populate the graph (example edges) */
    if (!addEdge(graph, 0, 1) ||
        !addEdge(graph, 0, 4) ||
        !addEdge(graph, 1, 2) ||
        !addEdge(graph, 1, 3) ||
        !addEdge(graph, 1, 4) ||
        !addEdge(graph, 2, 3) ||
        !addEdge(graph, 3, 4)) {
        fprintf(stderr, "Error: failed to add one or more edges.\n");
        freeGraph(graph);
        return EXIT_FAILURE;
    }

    /* ... (graph processing logic would go here) ... */

    /* Clean up */
    freeGraph(graph);
    return EXIT_SUCCESS;
}
